const DRUG_DATA = [{"s":"abecma","b":"Abecma","g":"idecabtagene vicleucel","c":"CAR T-Cell Therapy (BCMA-targeted)","a":"","m":"Bristol-Myers Squibb (Celgene/bluebird bio)","i":"Multiple myeloma \u2014 relapsed or refractory, after four or more prior lines of therapy including an immunomodulatory agent, a proteasome inhibitor, and an anti-CD38 monoclonal antibody","d":"Multiple myeloma \u2014 relapsed or refractory, after four or more prior lines of therapy including an immunomodulatory agent, a proteasome inhibitor, and an anti-CD38 monoclonal antibody","ae":"CRS (84%), neutropenia (89%), anemia (60%), thrombocytopenia (52%), infections (69%), fatigue (40%), musculoskeletal pain (36%), nausea (28%), diarrhea (25%), encephalopathy/confusional state (18%), headache (16%), febrile neutropenia (16%), hypogammaglobulinemia (21%)","moa":"Idecabtagene vicleucel is a BCMA-directed genetically modified autologous T-cell immunotherapy. Patient T cells are collected via leukapheresis and genetically modified ex vivo with a lentiviral vector encoding a chimeric antigen receptor (CAR) comprising an anti-BCMA single-chain variable fragment (scFv) linked to a 4-1BB costimulatory domain and CD3-zeta signaling domain. Upon binding BCMA on my","pk":"Peak CAR T-cell expansion: median 11-13 days post-infusion. CAR T cells detectable in blood for 6+ months. No traditional PK parameters apply (cell-based therapy). Persistence correlated with response duration.","t":[]},{"s":"adcetris","b":"Adcetris","g":"brentuximab vedotin","c":"Antibody-Drug Conjugate (CD30-targeted)","a":"FDA Approved 2011","m":"Seagen (Pfizer)","i":"Classical Hodgkin lymphoma (cHL) \u2014 previously untreated Stage III or IV (with doxorubicin, vinblastine, and dacarbazine); post-ASCT consolidation in patients at high risk of relapse or progression; after failure of ASCT or \u22652 prior multi-agent chemotherapy regimens; Systemic anaplastic large cell lymphoma (sALCL) \u2014 previously untreated (with CHP), or after failure of at least one prior multi-agent chemotherapy regimen; Primary cutaneous anaplastic large cell lymphoma (pcALCL) or CD30-expressing ","d":"Classical Hodgkin lymphoma (cHL) \u2014 previously untreated Stage III or IV (with doxorubicin, vinblastine, and dacarbazine); post-ASCT consolidation in patients at high risk of relapse or progression; after failure of ASCT or \u22652 prior multi-agent chemotherapy regimens; Systemic anaplastic large cell lymphoma (sALCL) \u2014 previously untreated (with CHP), or after failure of at least one prior multi-agent","ae":"Peripheral neuropathy (67%), fatigue (49%), nausea (42%), diarrhea (36%), neutropenia (39%), upper respiratory tract infection (25%), pyrexia (24%), constipation (16%), vomiting (17%), alopecia (13%)","moa":"Brentuximab vedotin is an antibody-drug conjugate consisting of a chimeric anti-CD30 IgG1 antibody conjugated to monomethyl auristatin E (MMAE), a microtubule-disrupting agent, via a protease-cleavable linker. It binds CD30 on the cell surface and is internalized, releasing MMAE which binds to tubulin and disrupts the microtubule network, inducing cell cycle arrest and apoptotic death of CD30-expr","pk":"ADC half-life: approximately 4-6 days. MMAE (payload) half-life: 3-4 days. Tmax (ADC): end of infusion. Vd: approximately 6-10 L. Clearance: 1.46 L/day. Steady-state by approximately Cycle 3. MMAE is metabolized by CYP3A4. Primarily excreted in feces (72%) and urine (28%).","t":[{"name":"SG035-0003","desc":"Brentuximab vedotin in relapsed/refractory Hodgkin lymphoma after auto-SCT. Phase II, n=102."},{"name":"ECHELON-1","desc":"Brentuximab vedotin + AVD vs. ABVD in 1L advanced Hodgkin lymphoma. Phase III, n=1334."}]},{"s":"afinitor","b":"Afinitor","g":"everolimus","c":"mTOR Inhibitor","a":"FDA Approved 2009","m":"Novartis","i":"Advanced hormone receptor-positive/HER2-negative breast cancer (with exemestane, after letrozole or anastrozole failure); Advanced renal cell carcinoma after failure of sunitinib or sorafenib; Progressive neuroendocrine tumors of pancreatic origin (PNET); Progressive, well-differentiated, non-functional neuroendocrine tumors of GI or lung origin; Renal angiomyolipoma with TSC; Subependymal giant cell astrocytoma (SEGA) with TSC","d":"Advanced hormone receptor-positive/HER2-negative breast cancer (with exemestane, after letrozole or anastrozole failure); Advanced renal cell carcinoma after failure of sunitinib or sorafenib; Progressive neuroendocrine tumors of pancreatic origin (PNET); Progressive, well-differentiated, non-functional neuroendocrine tumors of GI or lung origin; Renal angiomyolipoma with TSC; Subependymal giant c","ae":"","moa":"Everolimus is an inhibitor of mammalian target of rapamycin (mTOR), a serine/threonine kinase downstream of the PI3K/AKT pathway. Everolimus binds to FKBP-12, and this complex inhibits mTOR complex 1 (mTORC1), reducing protein synthesis, cell proliferation, and angiogenesis in tumor cells.","pk":"Tmax: 1-2 hours. Half-life: approximately 30 hours. Protein binding: ~74%. Metabolized by CYP3A4 and P-gp. Steady-state reached in 2 weeks. Blood-to-plasma ratio: 17-73%. Excreted in feces (80%) and urine (5%).","t":[{"name":"RECORD-1","desc":"Everolimus vs. placebo in advanced RCC after VEGFR-TKI failure. Phase III, n=416."},{"name":"BOLERO-2","desc":"Everolimus + exemestane vs. placebo + exemestane in HR+/HER2- advanced breast cancer. Phase III, n=724."}]},{"s":"alecensa","b":"Alecensa","g":"alectinib","c":"ALK TKI (2nd Generation)","a":"FDA Approved 2015","m":"Genentech/Roche","i":"ALK-Positive NSCLC: Adult patients with ALK-positive metastatic NSCLC as detected by an FDA-approved test. Adjuvant ALK-Positive NSCLC: Adjuvant treatment following tumor resection in adult patients with ALK-positive NSCLC as detected by an FDA-approved test.","d":"ALK-Positive NSCLC: Adult patients with ALK-positive metastatic NSCLC as detected by an FDA-approved test. Adjuvant ALK-Positive NSCLC: Adjuvant treatment following tumor resection in adult patients with ALK-positive NSCLC as detected by an FDA-approved test.","ae":"","moa":"Alectinib is a second-generation ALK inhibitor that targets ALK and RET receptor tyrosine kinases. It inhibits ALK phosphorylation and ALK-mediated activation of downstream signaling pathways including STAT3, AKT, and ERK1/2. Alectinib is active against multiple ALK resistance mutations, including the L1196M gatekeeper mutation. It demonstrates CNS penetration and activity against brain metastases","pk":"Tmax: 4 hours (fed). Bioavailability: 37% with food. Vd: 4016 L. Protein binding: >99%. Metabolized by CYP3A4 to active metabolite M4 (similar potency). Half-life: 33 hours (alectinib), 31 hours (M4). Steady state in 7 days. Elimination: feces 98%, urine","t":[{"name":"ALEX","desc":"Alectinib vs. crizotinib in first-line ALK+ advanced NSCLC. Phase III, n=303."},{"name":"ALINA","desc":"Adjuvant alectinib vs. platinum-based chemotherapy in resected ALK+ NSCLC (stage IB-IIIA). Phase III, n=257."}]},{"s":"alimta","b":"Alimta","g":"","c":"Antifolate Antimetabolite","a":"FDA Approved 2004","m":"Eli Lilly","i":"Non-squamous non-small cell lung cancer \u2014 initial treatment in combination with cisplatin (locally advanced or metastatic); maintenance treatment after 4 cycles of non-pemetrexed platinum-based chemotherapy; single agent after prior chemotherapy; Malignant pleural mesothelioma \u2014 in combination with cisplatin (unresectable or non-surgical candidates).","d":"Non-squamous non-small cell lung cancer \u2014 initial treatment in combination with cisplatin (locally advanced or metastatic); maintenance treatment after 4 cycles of non-pemetrexed platinum-based chemotherapy; single agent after prior chemotherapy; Malignant pleural mesothelioma \u2014 in combination with cisplatin (unresectable or non-surgical candidates).","ae":"","moa":"","pk":"","t":[{"name":"JMEI","desc":"Pemetrexed vs. docetaxel in 2L advanced NSCLC. Phase III, n=571."}]},{"s":"arranon","b":"Arranon","g":"nelarabine","c":"Purine Nucleoside Analog (Deoxyguanosine)","a":"FDA Approved 2005","m":"Novartis","i":"T-cell acute lymphoblastic leukemia (T-ALL) and T-cell lymphoblastic lymphoma (T-LBL) in patients whose disease has not responded to or has relapsed following treatment with at least two chemotherapy regimens.","d":"T-cell acute lymphoblastic leukemia (T-ALL) and T-cell lymphoblastic lymphoma (T-LBL) in patients whose disease has not responded to or has relapsed following treatment with at least two chemotherapy regimens.","ae":"Fatigue (50%), nausea (41%), somnolence (23%), diarrhea (22%), peripheral neuropathy (21%), vomiting (22%), anemia (99% any grade), thrombocytopenia (86%), neutropenia (81%), hypoesthesia (17%), cough (25%), dyspnea (20%)","moa":"Nelarabine is a prodrug of ara-G (9-\u03b2-D-arabinofuranosylguanine), a deoxyguanosine analog. It is demethylated by adenosine deaminase (ADA) to ara-G, which is then phosphorylated intracellularly to the active triphosphate ara-GTP. Ara-GTP accumulates preferentially in T-cells due to higher dGTP levels and is incorporated into DNA during synthesis, leading to inhibition of DNA synthesis and cell dea","pk":"Nelarabine and ara-G are rapidly eliminated; nelarabine t\u00bd: ~30 min, ara-G t\u00bd: ~3 hours. Nelarabine is partially protein bound (","t":[]},{"s":"avastin","b":"Avastin","g":"bevacizumab","c":"VEGF Inhibitor (Anti-Angiogenic)","a":"FDA Approved 2004","m":"Genentech","i":"Metastatic colorectal cancer (with IV 5-FU-based chemotherapy); Non-squamous non-small cell lung cancer (with carboplatin and paclitaxel, first-line); Recurrent glioblastoma; Metastatic renal cell carcinoma (with interferon alfa); Cervical cancer (persistent, recurrent, or metastatic, with chemo); Epithelial ovarian, fallopian tube, or primary peritoneal cancer (multiple settings); Hepatocellular carcinoma (with atezolizumab)","d":"Metastatic colorectal cancer (with IV 5-FU-based chemotherapy); Non-squamous non-small cell lung cancer (with carboplatin and paclitaxel, first-line); Recurrent glioblastoma; Metastatic renal cell carcinoma (with interferon alfa); Cervical cancer (persistent, recurrent, or metastatic, with chemo); Epithelial ovarian, fallopian tube, or primary peritoneal cancer (multiple settings); Hepatocellular ","ae":"","moa":"Bevacizumab is a recombinant humanized IgG1 monoclonal antibody that binds to vascular endothelial growth factor (VEGF), preventing its interaction with VEGF receptors (Flt-1 and KDR) on endothelial cells. This inhibits tumor angiogenesis, reducing tumor blood supply and growth.","pk":"Half-life: approximately 20 days (range 11-50 days). Clearance: 0.23 L/day. Vd: 2.7-3.2 L. Steady-state at ~100 days. No significant metabolism (IgG catabolism).","t":[{"name":"E4599","desc":"Bevacizumab + carboplatin/paclitaxel vs. chemo alone in advanced nonsquamous NSCLC. Phase III, n=878."}]},{"s":"bavencio","b":"Bavencio","g":"avelumab","c":"PD-L1 Inhibitor","a":"FDA Approved 2017","m":"EMD Serono/Pfizer","i":"Merkel cell carcinoma (MCC) \u2014 metastatic, for adults and pediatric patients 12 years and older (including first-line); Locally advanced or metastatic urothelial carcinoma (UC) \u2014 maintenance treatment in patients whose disease has not progressed with first-line platinum-containing chemotherapy","d":"Merkel cell carcinoma (MCC) \u2014 metastatic, for adults and pediatric patients 12 years and older (including first-line); Locally advanced or metastatic urothelial carcinoma (UC) \u2014 maintenance treatment in patients whose disease has not progressed with first-line platinum-containing chemotherapy","ae":"Fatigue (32%), musculoskeletal pain (17%), diarrhea (16%), nausea (14%), infusion-related reactions (25%), rash (15%), decreased appetite (13%), peripheral edema (13%), urinary tract infection (11%)","moa":"Avelumab is a human IgG1\u03bb monoclonal antibody that binds PD-L1 and blocks its interaction with PD-1 and B7.1 (CD80). This releases PD-L1-mediated suppression of anti-tumor T-cell responses. Unlike other anti-PD-L1 antibodies, avelumab has a wild-type IgG1 Fc region that retains the ability to engage innate immune effector cells and mediate antibody-dependent cell-mediated cytotoxicity (ADCC).","pk":"Half-life: 6.1 days. Clearance: 0.59 L/day. Vd: 4.7 L. Steady-state by ~4-6 weeks with q2w dosing. Linear PK across 1-20 mg/kg range.","t":[]},{"s":"besponsa","b":"Besponsa","g":"inotuzumab ozogamicin","c":"","a":"","m":"","i":"B-cell precursor acute lymphoblastic leukemia (ALL) \u2014 relapsed or refractory, in adults","d":"B-cell precursor acute lymphoblastic leukemia (ALL) \u2014 relapsed or refractory, in adults","ae":"Thrombocytopenia (51%), neutropenia (49%), infection (48%), anemia (36%), leukopenia (35%), fatigue (35%), hemorrhage (33%), pyrexia (32%), nausea (31%), headache (28%), febrile neutropenia (26%), transaminase increased (26%), abdominal pain (23%), GGT increase (21%), hyperbilirubinemia (21%)","moa":"Inotuzumab ozogamicin is an antibody-drug conjugate composed of a humanized anti-CD22 IgG4 monoclonal antibody conjugated to calicheamicin (N-acetyl-gamma-calicheamicin dimethylhydrazide), a cytotoxic agent, via an acid-labile linker. Upon binding to CD22 on B-cell ALL blasts, the ADC is internalized, and the acidic environment of lysosomes releases calicheamicin, which binds to the minor groove o","pk":"Half-life: approximately 12.3 days. Clearance decreases over time as CD22+ cells are depleted. Steady-state reached by Cycle 4. Vd: approximately 12 L. Metabolism via payload (calicheamicin) hydrolysis.","t":[]},{"s":"blincyto","b":"Blincyto","g":"blinatumomab","c":"","a":"","m":"","i":"B-cell precursor acute lymphoblastic leukemia (ALL) \u2014 relapsed or refractory; Philadelphia chromosome-negative, CD19-positive, in first or second complete remission with minimal residual disease (MRD) \u22650.1%; Newly diagnosed Philadelphia chromosome-positive in combination with a TKI","d":"B-cell precursor acute lymphoblastic leukemia (ALL) \u2014 relapsed or refractory; Philadelphia chromosome-negative, CD19-positive, in first or second complete remission with minimal residual disease (MRD) \u22650.1%; Newly diagnosed Philadelphia chromosome-positive in combination with a TKI","ae":"Pyrexia (62%), headache (36%), infections (34%), infusion-related reactions (30%), nausea (25%), tremor (20%), edema (16%), febrile neutropenia (16%), constipation (15%), anemia (15%), diarrhea (14%), fatigue (13%)","moa":"Blinatumomab is a bispecific T-cell engager (BiTE) antibody construct consisting of two single-chain variable fragments (scFvs) \u2014 one binding CD19 on B cells and one binding CD3 on T cells. By simultaneously bridging T cells and CD19-positive B cells, it activates endogenous T cells to release perforin and granzymes, inducing apoptosis and lysis of CD19-positive target cells independent of MHC res","pk":"Estimated half-life: 2.1 hours. Steady-state serum concentration (Css) reached within 1 day of continuous IV infusion. Clearance: 3.1 L/h. Vd: 4.4 L. Not expected to be metabolized by CYP enzymes.","t":[{"name":"TOWER","desc":"Blinatumomab vs. standard chemo in relapsed/refractory B-ALL. Phase III, n=405."}]},{"s":"bosulif","b":"Bosulif","g":"","c":"BCR-ABL/SRC Kinase Inhibitor","a":"FDA Approved 2012","m":"Pfizer","i":"Newly diagnosed chronic phase Ph+ CML in adults; Chronic, accelerated, or blast phase Ph+ CML with resistance or intolerance to prior therapy in adults and pediatric patients \u22651 year.","d":"Newly diagnosed chronic phase Ph+ CML in adults; Chronic, accelerated, or blast phase Ph+ CML with resistance or intolerance to prior therapy in adults and pediatric patients \u22651 year.","ae":"","moa":"","pk":"","t":[{"name":"BFORE","desc":"Bosutinib vs. imatinib in newly diagnosed chronic-phase CML. Phase III, n=536."}]},{"s":"breyanzi","b":"Breyanzi","g":"lisocabtagene maraleucel","c":"CAR T-Cell Therapy (CD19-targeted)","a":"FDA Approved 2021","m":"Bristol-Myers Squibb (Juno Therapeutics)","i":"Large B-cell lymphoma \u2014 relapsed or refractory after two or more lines of systemic therapy (DLBCL NOS, high-grade B-cell lymphoma, primary mediastinal large B-cell lymphoma, FL Grade 3B); relapsed or refractory within 12 months of first-line chemoimmunotherapy or refractory to first-line chemoimmunotherapy; Mantle cell lymphoma \u2014 relapsed or refractory; Follicular lymphoma (FL) \u2014 relapsed or refractory after two or more lines","d":"Large B-cell lymphoma \u2014 relapsed or refractory after two or more lines of systemic therapy (DLBCL NOS, high-grade B-cell lymphoma, primary mediastinal large B-cell lymphoma, FL Grade 3B); relapsed or refractory within 12 months of first-line chemoimmunotherapy or refractory to first-line chemoimmunotherapy; Mantle cell lymphoma \u2014 relapsed or refractory; Follicular lymphoma (FL) \u2014 relapsed or refra","ae":"CRS (46%), fatigue (42%), musculoskeletal pain (34%), nausea (33%), headache (30%), encephalopathy (27%), infections (45%), fever (26%), diarrhea (22%), hypotension (22%), tachycardia (18%), neutropenia (65%), anemia (50%), thrombocytopenia (42%)","moa":"Lisocabtagene maraleucel is a CD19-directed genetically modified autologous T-cell immunotherapy composed of separately manufactured CD8+ and CD4+ T-cell populations transduced with a lentiviral vector encoding a CAR targeting CD19, with a 4-1BB costimulatory domain and CD3-zeta signaling domain. The defined composition (equal ratio of CD8+ and CD4+ components) is designed to improve consistency a","pk":"Peak CAR T-cell expansion: median 11 days. CAR T cells detectable for months. Cellular kinetics: higher peak expansion associated with higher response rates. No traditional PK.","t":[]},{"s":"brukinsa","b":"Brukinsa","g":"zanubrutinib","c":"","a":"FDA Approved 2019","m":"BeiGene","i":"Mantle cell lymphoma (MCL) in adults who have received at least one prior therapy; Waldenstr\u00f6m's macroglobulinemia (WM); Marginal zone lymphoma (MZL) who have received at least one prior anti-CD20-based regimen; Chronic lymphocytic leukemia (CLL) or small lymphocytic lymphoma (SLL)","d":"Mantle cell lymphoma (MCL) in adults who have received at least one prior therapy; Waldenstr\u00f6m's macroglobulinemia (WM); Marginal zone lymphoma (MZL) who have received at least one prior anti-CD20-based regimen; Chronic lymphocytic leukemia (CLL) or small lymphocytic lymphoma (SLL)","ae":"Neutropenia (30%), upper respiratory tract infection (24%), hemorrhage/bruising (22%), musculoskeletal pain (20%), rash (17%), diarrhea (15%), cough (14%), fatigue (13%), pneumonia (12%)","moa":"Zanubrutinib is a small-molecule inhibitor of Bruton's tyrosine kinase (BTK). It forms a covalent bond with a cysteine residue (C481) in the BTK active site, leading to sustained inhibition of BTK enzymatic activity. BTK is a signaling molecule in the B-cell receptor (BCR) pathway; its inhibition reduces malignant B-cell proliferation, trafficking, chemotaxis, and adhesion.","pk":"Median Tmax: 2 hours. Steady-state AUC increased dose-proportionally. Half-life: approximately 2-4 hours. Metabolized primarily by CYP3A. Excreted in feces (87%) and urine (8%).","t":[{"name":"ALPINE","desc":"Zanubrutinib vs. ibrutinib in relapsed/refractory CLL/SLL. Phase III, n=652."}]},{"s":"cabometyx","b":"Cabometyx","g":"cabozantinib","c":"","a":"FDA Approved 2016","m":"Exelixis","i":"Advanced renal cell carcinoma (RCC) \u2014 as monotherapy or in combination with nivolumab (first-line); Hepatocellular carcinoma (HCC) previously treated with sorafenib; Locally advanced or metastatic differentiated thyroid cancer (DTC) that has progressed following prior VEGFR-targeted therapy and who are radioactive iodine-refractory or ineligible","d":"Advanced renal cell carcinoma (RCC) \u2014 as monotherapy or in combination with nivolumab (first-line); Hepatocellular carcinoma (HCC) previously treated with sorafenib; Locally advanced or metastatic differentiated thyroid cancer (DTC) that has progressed following prior VEGFR-targeted therapy and who are radioactive iodine-refractory or ineligible","ae":"Diarrhea (63%), fatigue (56%), PPE/hand-foot syndrome (45%), decreased appetite (46%), hypertension (37%), nausea (35%), vomiting (24%), weight decreased (24%), dysgeusia (19%), stomatitis (22%)","moa":"Cabozantinib is an inhibitor of multiple receptor tyrosine kinases including VEGF receptors (VEGFR1, VEGFR2, VEGFR3), MET (hepatocyte growth factor receptor), AXL, RET, ROS1, TYRO3, MER, KIT, TRKB, FLT3, and TIE-2. These receptor tyrosine kinases are involved in tumor angiogenesis, invasion, metastasis, and tumor microenvironment modulation.","pk":"Tmax: 2-5 hours. Half-life: approximately 99 hours. Protein binding: \u226599.7%. Metabolized primarily by CYP3A4. Fecal excretion (54%), urinary excretion (27%).","t":[{"name":"METEOR","desc":"CC, 2nd-line) \u2014 Cabozantinib vs. everolimus in advanced RCC after prior VEGFR-targeted therapy. Phase III, n=658."},{"name":"CABOSUN","desc":"CC, 1st-line) \u2014 Cabozantinib vs. sunitinib as initial therapy for intermediate/poor-risk mRCC. Phase II (Alliance A031203), n=157."},{"name":"CELESTIAL","desc":"CC, 2nd-line) \u2014 Cabozantinib vs. placebo in previously treated advanced HCC. Phase III, n=707."}]},{"s":"calquence","b":"Calquence","g":"acalabrutinib","c":"BTK Inhibitor","a":"FDA Approved 2017","m":"AstraZeneca","i":"Chronic lymphocytic leukemia (CLL) or small lymphocytic lymphoma (SLL) \u2014 in adult patients; Mantle cell lymphoma (MCL) \u2014 in adults who have received at least one prior therapy","d":"Chronic lymphocytic leukemia (CLL) or small lymphocytic lymphoma (SLL) \u2014 in adult patients; Mantle cell lymphoma (MCL) \u2014 in adults who have received at least one prior therapy","ae":"Headache (38%), diarrhea (31%), musculoskeletal pain (25%), infection (upper respiratory tract 22%), bruising (21%), neutropenia (19%), fatigue (14%), nausea (13%), cough (11%), abdominal pain (9%)","moa":"Acalabrutinib is a selective, irreversible, small-molecule inhibitor of Bruton's tyrosine kinase (BTK). It forms a covalent bond with cysteine 481 in the BTK active site. Acalabrutinib and its active metabolite (ACP-5862) inhibit BTK-mediated activation of downstream signaling proteins CD86 and CD69, inhibiting malignant B-cell proliferation and survival. Acalabrutinib was designed for greater BTK","pk":"Tmax: 0.75-1 hour. Half-life: ~1 hour (parent); active metabolite (ACP-5862) t\u00bd ~3.5 hours. Protein binding: 97.5%. Metabolized by CYP3A (active metabolite ~50% of parent exposure). Excreted in feces (84%) and urine (12%).","t":[{"name":"ASCEND","desc":"Acalabrutinib vs. idelalisib/rituximab or BR in relapsed/refractory CLL. Phase III, n=310."}]},{"s":"caprelsa","b":"Caprelsa","g":"vandetanib","c":"Multi-Kinase Inhibitor (EGFR/VEGFR/RET)","a":"FDA Approved 2011","m":"Sanofi Genzyme","i":"Symptomatic or progressive medullary thyroid cancer (MTC) in patients with unresectable, locally advanced, or metastatic disease. Use is restricted to patients with MTC who are symptomatic or progressive and for whom no locally curative surgical options exist.","d":"Symptomatic or progressive medullary thyroid cancer (MTC) in patients with unresectable, locally advanced, or metastatic disease. Use is restricted to patients with MTC who are symptomatic or progressive and for whom no locally curative surgical options exist.","ae":"Diarrhea (57%), rash (53%), acne (35%), nausea (33%), hypertension (33%), headache (26%), fatigue (24%), decreased appetite (21%), abdominal pain (21%), QTc prolongation (36%)","moa":"Vandetanib is an inhibitor of multiple receptor tyrosine kinases including VEGFR-2 (KDR), EGFR (HER1), RET, BRK, TIE2, members of the EPH receptor family, and Src kinase family members. RET kinase inhibition is particularly relevant for medullary thyroid cancer, which frequently harbors activating RET mutations. The combined anti-VEGFR and anti-EGFR activity provides both anti-angiogenic and direc","pk":"Tmax: median 6 hours (range 4-10). Half-life: 19 days. Protein binding: ~90%. Metabolized by CYP3A4. Steady-state at ~3 months. Excreted in feces (44%) and urine (25%).","t":[{"name":"ZETA","desc":"Vandetanib vs. placebo in advanced medullary thyroid cancer. Phase III, n=331."}]},{"s":"carvykti","b":"Carvykti","g":"ciltacabtagene autoleucel","c":"CAR T-Cell Therapy (BCMA-targeted)","a":"","m":"Janssen/Legend Biotech","i":"Multiple myeloma \u2014 relapsed or refractory, after four or more prior lines of therapy including a proteasome inhibitor, an immunomodulatory agent, and an anti-CD38 monoclonal antibody","d":"Multiple myeloma \u2014 relapsed or refractory, after four or more prior lines of therapy including a proteasome inhibitor, an immunomodulatory agent, and an anti-CD38 monoclonal antibody","ae":"CRS (95%), pyrexia (95%), neutropenia (95%), thrombocytopenia (80%), anemia (68%), musculoskeletal pain (57%), fatigue (42%), infections (57%), GI disorders (48%), encephalopathy (21%), lymphopenia (19%)","moa":"Ciltacabtagene autoleucel is a BCMA-directed genetically modified autologous T-cell immunotherapy. Patient T cells are transduced with a lentiviral vector encoding a CAR containing two BCMA-targeting single-domain antibodies (VHH) designed to confer high-avidity binding, linked to a 4-1BB costimulatory domain and CD3-zeta signaling domain. The dual-binding VHH design differentiates it from other B","pk":"Peak CAR T-cell expansion: median 10-14 days. T cells detectable in blood for 6+ months. Higher Cmax associated with greater depth of response. Primarily distributed in peripheral blood and bone marrow.","t":[{"name":"CARTITUDE-1","desc":"Ciltacabtagene autoleucel in heavily pretreated relapsed/refractory MM. Phase Ib/II, n=97."}]},{"s":"ccnu","b":"ccnu","g":"","c":"","a":"","m":"","i":"","d":"","ae":"","moa":"","pk":"","t":[]},{"s":"ceenu-gleostine","b":"CeeNU / Gleostine","g":"lomustine (CCNU)","c":"Nitrosourea Alkylating Agent","a":"FDA Approved 1976","m":"NextSource Biotechnology","i":"Brain tumors \u2014 both primary and metastatic, in patients who have already received appropriate surgical and/or radiotherapeutic procedures; Hodgkin lymphoma \u2014 as secondary therapy in combination with other approved drugs in patients who relapse while being treated with primary therapy, or who fail to respond to primary therapy.","d":"Brain tumors \u2014 both primary and metastatic, in patients who have already received appropriate surgical and/or radiotherapeutic procedures; Hodgkin lymphoma \u2014 as secondary therapy in combination with other approved drugs in patients who relapse while being treated with primary therapy, or who fail to respond to primary therapy.","ae":"Nausea and vomiting (within 3-6 hours, lasting 24 hours), thrombocytopenia (65%), leukopenia (63%), anemia (common), stomatitis (5%), alopecia (common), hepatotoxicity (transient, reversible), pulmonary toxicity (dose-cumulative)","moa":"Lomustine (CCNU) is a nitrosourea alkylating agent that undergoes spontaneous chemical decomposition to form reactive intermediates. These intermediates alkylate DNA and RNA, forming interstrand cross-links and single-strand breaks. The chloroethyl moiety generates chloroethyl-diazonium ions that alkylate DNA at the O6-position of guanine, producing O6-chloroethylguanine adducts that rearrange to ","pk":"Rapidly absorbed orally. Extensively metabolized hepatically (CYP enzymes) to active metabolites. Half-life of metabolites: 16-48 hours. Crosses blood-brain barrier (CSF levels 15-30% of plasma). Primarily excreted renally (50% within 12 hours).","t":[]},{"s":"clolar","b":"Clolar","g":"clofarabine","c":"Purine Nucleoside Antimetabolite","a":"FDA Approved 2004","m":"Sanofi Genzyme","i":"Relapsed or refractory acute lymphoblastic leukemia (ALL) in pediatric patients 1 to 21 years of age, after at least two prior regimens.","d":"Relapsed or refractory acute lymphoblastic leukemia (ALL) in pediatric patients 1 to 21 years of age, after at least two prior regimens.","ae":"Vomiting (83%), nausea (75%), febrile neutropenia (57%), diarrhea (56%), pruritus (47%), headache (46%), pyrexia (41%), dermatitis (41%), rigors (38%), abdominal pain (36%), fatigue (36%), tachycardia (35%), epistaxis (31%), anorexia (30%), petechiae (29%), hepatomegaly (25%)","moa":"Clofarabine is a purine nucleoside antimetabolite. It is phosphorylated intracellularly to the active triphosphate (clofarabine-5'-triphosphate), which inhibits DNA polymerases and ribonucleotide reductase. Inhibition of ribonucleotide reductase depletes deoxyribonucleotide pools needed for DNA synthesis. Incorporation into DNA causes chain termination and induces apoptosis. The 2'-fluoro and 2'-c","pk":"Half-life: approximately 5.2 hours. Vd: 172 L/m\u00b2. Protein binding: 47%. Not appreciably metabolized; 49-60% excreted unchanged in urine. CrCl-dependent clearance.","t":[{"name":"CLO-212","desc":"Clofarabine in pediatric relapsed/refractory ALL. Phase II, n=61."}]},{"s":"columvi","b":"Columvi","g":"glofitamab-gxbm","c":"Bispecific Antibody (CD20 \u00d7 CD3)","a":"FDA Approved 2023","m":"Genentech","i":"Diffuse large B-cell lymphoma (DLBCL) \u2014 relapsed or refractory, after two or more lines of systemic therapy","d":"Diffuse large B-cell lymphoma (DLBCL) \u2014 relapsed or refractory, after two or more lines of systemic therapy","ae":"CRS (44%), musculoskeletal pain (28%), neutropenia (37%), fatigue (24%), rash (22%), infections (40%), diarrhea (14%), pyrexia (13%)","moa":"Glofitamab is a bispecific T-cell engaging antibody with a novel 2:1 molecular format \u2014 it has two binding domains for CD20 on B cells and one for CD3 on T cells. This 2:1 configuration provides bivalent binding to CD20, resulting in higher avidity for CD20-expressing tumor cells. Obinutuzumab pre-treatment depletes circulating B cells, reducing the risk of severe CRS during glofitamab step-up dos","pk":"Half-life: approximately 17 days at 30 mg target dose. Non-linear PK at lower step-up doses. Steady-state by Cycle 3. Clearance decreases with repeated dosing as CD20+ cells are depleted.","t":[{"name":"NP30179","desc":"Glofitamab in relapsed/refractory DLBCL after \u22652 prior therapies. Phase I/II, n=154."}]},{"s":"cyramza","b":"Cyramza","g":"ramucirumab","c":"VEGFR-2 Antagonist","a":"FDA Approved 2014","m":"Eli Lilly","i":"Gastric or gastroesophageal junction (GEJ) adenocarcinoma (as single agent or with paclitaxel, after prior fluoropyrimidine- or platinum-containing chemotherapy); Metastatic non-small cell lung cancer (with docetaxel, after progression on platinum-based chemotherapy; with erlotinib first-line for EGFR exon 19 deletions or exon 21 L858R mutations); Metastatic colorectal cancer (with FOLFIRI, after progression on bevacizumab/oxaliplatin/fluoropyrimidine); Hepatocellular carcinoma (as single agent ","d":"Gastric or gastroesophageal junction (GEJ) adenocarcinoma (as single agent or with paclitaxel, after prior fluoropyrimidine- or platinum-containing chemotherapy); Metastatic non-small cell lung cancer (with docetaxel, after progression on platinum-based chemotherapy; with erlotinib first-line for EGFR exon 19 deletions or exon 21 L858R mutations); Metastatic colorectal cancer (with FOLFIRI, after ","ae":"Hypertension (26%), diarrhea (14%), headache (9%), hyponatremia (6%), proteinuria (3-17% depending on indication), epistaxis (12%)","moa":"Ramucirumab is a human IgG1 monoclonal antibody that specifically binds to VEGF Receptor 2 (VEGFR2), blocking the binding of VEGF-A, VEGF-C, and VEGF-D ligands. This inhibits ligand-stimulated activation of VEGFR2, thereby inhibiting ligand-induced proliferation and migration of human endothelial cells and reducing tumor vascularity and growth.","pk":"Half-life: approximately 14 days. Clearance: 0.015 L/h. Steady-state reached by approximately the 6th dose with every-2-week dosing.","t":[{"name":"REGARD","desc":"Ramucirumab vs. placebo in advanced gastric/GEJ adenocarcinoma after 1L chemo. Phase III, n=355."},{"name":"REVEL","desc":"Ramucirumab + docetaxel vs. placebo + docetaxel in 2L advanced NSCLC. Phase III, n=1253."}]},{"s":"darzalex","b":"Darzalex","g":"daratumumab","c":"","a":"","m":"Janssen","i":"Newly diagnosed multiple myeloma (in combination with various regimens including bortezomib/melphalan/prednisone, lenalidomide/dexamethasone, or bortezomib/thalidomide/dexamethasone); Relapsed/refractory multiple myeloma (in various combinations or as monotherapy after \u22653 prior lines); Light chain (AL) amyloidosis","d":"Newly diagnosed multiple myeloma (in combination with various regimens including bortezomib/melphalan/prednisone, lenalidomide/dexamethasone, or bortezomib/thalidomide/dexamethasone); Relapsed/refractory multiple myeloma (in various combinations or as monotherapy after \u22653 prior lines); Light chain (AL) amyloidosis","ae":"","moa":"Daratumumab is a human IgG1\u03ba monoclonal antibody that binds to CD38, a transmembrane glycoprotein highly expressed on multiple myeloma cells. It induces tumor cell death through complement-dependent cytotoxicity (CDC), antibody-dependent cellular cytotoxicity (ADCC), antibody-dependent cellular phagocytosis, and direct apoptosis via Fc-mediated cross-linking.","pk":"Half-life: approximately 18 \u00b1 9 days. Clearance: 171 \u00b1 81 mL/day. Vd: 4.7 \u00b1 1.3 L. Steady-state reached by approximately 5 months of weekly dosing. Linear PK at doses \u22651 mg/kg.","t":[{"name":"CASTOR","desc":"Daratumumab + bortezomib/dex vs. bortezomib/dex in relapsed MM. Phase III, n=498."},{"name":"POLLUX","desc":"Daratumumab + lenalidomide/dex vs. lenalidomide/dex in relapsed MM. Phase III, n=569."}]},{"s":"doxil","b":"Doxil","g":"doxorubicin HCl liposome injection","c":"Anthracycline (Liposomal)","a":"FDA Approved 1995","m":"Baxter/Janssen","i":"Ovarian cancer \u2014 patients whose disease has progressed or recurred after platinum-based chemotherapy; AIDS-related Kaposi's sarcoma \u2014 after failure of prior systemic chemotherapy or intolerance; Multiple myeloma \u2014 in combination with bortezomib, in patients who have not previously received bortezomib and have received at least one prior therapy","d":"Ovarian cancer \u2014 patients whose disease has progressed or recurred after platinum-based chemotherapy; AIDS-related Kaposi's sarcoma \u2014 after failure of prior systemic chemotherapy or intolerance; Multiple myeloma \u2014 in combination with bortezomib, in patients who have not previously received bortezomib and have received at least one prior therapy","ae":"PPE/hand-foot syndrome (50%), stomatitis (41%), nausea (37%), fatigue (23%), vomiting (21%), rash (22%), diarrhea (18%), constipation (13%), neutropenia (12%), anemia (6%)","moa":"Doxil is a liposomal formulation of doxorubicin encapsulated in STEALTH liposomes (polyethylene glycol-coated). The PEG coating creates a protective layer that allows prolonged circulation time, and the small size (100 nm) enables accumulation in tumors through the enhanced permeability and retention (EPR) effect. Once internalized, doxorubicin intercalates DNA base pairs, inhibits topoisomerase I","pk":"Half-life: approximately 55 hours at 50 mg/m\u00b2. Plasma clearance: 0.041 L/h. Vd: 2.7 L. PEGylated liposomal formulation reduces RES clearance. Mostly confined to vascular space. Metabolized via doxorubicinol formation.","t":[]},{"s":"elrexfio","b":"Elrexfio","g":"elranatamab-bcmm","c":"Bispecific Antibody (BCMA \u00d7 CD3)","a":"FDA Approved 2023","m":"Pfizer","i":"Multiple myeloma \u2014 relapsed or refractory, after at least four prior lines of therapy including a proteasome inhibitor, an immunomodulatory agent, and an anti-CD38 monoclonal antibody","d":"Multiple myeloma \u2014 relapsed or refractory, after at least four prior lines of therapy including a proteasome inhibitor, an immunomodulatory agent, and an anti-CD38 monoclonal antibody","ae":"Infections (69%), CRS (58%), fatigue (37%), musculoskeletal pain (33%), diarrhea (29%), pneumonia (22%), nausea (20%), pyrexia (18%), injection site reactions (16%), neutropenia (56%), lymphopenia (83%), anemia (49%)","moa":"Elranatamab is a humanized bispecific IgG2 monoclonal antibody targeting BCMA on myeloma cells and CD3 on T cells. Similar to teclistamab, it redirects T cells to BCMA-expressing tumor cells, but uses a different IgG subclass and binding configuration.","pk":"Half-life: approximately 13 days at target dose. Step-up dosing reduces CRS risk. Steady-state by Cycle 4 with q2w maintenance. Non-linear PK due to target-mediated drug disposition.","t":[]},{"s":"empliciti","b":"Empliciti","g":"elotuzumab","c":"Anti-SLAMF7 Monoclonal Antibody","a":"","m":"Bristol-Myers Squibb","i":"Multiple myeloma \u2014 in combination with lenalidomide and dexamethasone, in patients who have received one to three prior therapies; in combination with pomalidomide and dexamethasone, in patients who have received at least two prior therapies including lenalidomide and a proteasome inhibitor","d":"Multiple myeloma \u2014 in combination with lenalidomide and dexamethasone, in patients who have received one to three prior therapies; in combination with pomalidomide and dexamethasone, in patients who have received at least two prior therapies including lenalidomide and a proteasome inhibitor","ae":"Fatigue (62%), diarrhea (47%), pyrexia (37%), constipation (36%), cough (34%), nausea (29%), pneumonia (20%), upper respiratory tract infection (23%), decreased appetite (21%), nasopharyngitis (17%), infusion reactions (10%)","moa":"Elotuzumab is a humanized IgG1 monoclonal antibody targeting SLAMF7 (Signaling Lymphocytic Activation Molecule Family member 7, also known as CS1 or CD319). SLAMF7 is highly expressed on myeloma cells and natural killer (NK) cells. Elotuzumab has a dual mechanism: it directly activates NK cells through SLAMF7-mediated signaling (enhancing cytotoxicity), and it facilitates the interaction between N","pk":"Half-life: mean ~82 hours. Linear PK from 10-20 mg/kg. Steady-state reached by Cycle 3 with weekly dosing. Clearance: 15.6 mL/day. Vd: 5.7 L.","t":[{"name":"ELOQUENT-2","desc":"Elotuzumab + lenalidomide/dex vs. lenalidomide/dex in relapsed/refractory MM. Phase III, n=646."}]},{"s":"enhertu","b":"Enhertu","g":"fam-trastuzumab deruxtecan-nxki","c":"","a":"FDA Approved 2019","m":"Daiichi Sankyo/AstraZeneca","i":"HER2-positive unresectable or metastatic breast cancer after prior anti-HER2-based regimen; HER2-low unresectable or metastatic breast cancer after prior chemotherapy (or endocrine therapy if HR-positive); HER2-positive locally advanced or metastatic gastric/GEJ adenocarcinoma after prior trastuzumab-based regimen; Unresectable or metastatic HER2-mutant non-small cell lung cancer after prior systemic therapy","d":"HER2-positive unresectable or metastatic breast cancer after prior anti-HER2-based regimen; HER2-low unresectable or metastatic breast cancer after prior chemotherapy (or endocrine therapy if HR-positive); HER2-positive locally advanced or metastatic gastric/GEJ adenocarcinoma after prior trastuzumab-based regimen; Unresectable or metastatic HER2-mutant non-small cell lung cancer after prior syste","ae":"","moa":"Fam-trastuzumab deruxtecan is an antibody-drug conjugate composed of a humanized anti-HER2 IgG1 monoclonal antibody covalently linked to a topoisomerase I inhibitor payload (DXd, an exatecan derivative) via a cleavable tetrapeptide-based linker. It targets HER2-expressing cells, undergoes internalization, and releases DXd intracellularly to cause DNA damage and tumor cell death. The membrane-perme","pk":"Tmax: end of infusion. Half-life: ADC ~5.7 days; DXd (payload) ~5.8 days. Vd: 3.8 L. Clearance: 0.42 L/day. Steady-state by Cycle 3. DXd metabolized by CYP3A4. Minimal renal excretion.","t":[]},{"s":"epkinly","b":"Epkinly","g":"epcoritamab-bysp","c":"Bispecific Antibody (CD20 \u00d7 CD3)","a":"FDA Approved 2023","m":"AbbVie/Genmab","i":"Diffuse large B-cell lymphoma (DLBCL) \u2014 relapsed or refractory, after two or more lines of systemic therapy; Follicular lymphoma (FL) \u2014 relapsed or refractory, after two or more lines of systemic therapy","d":"Diffuse large B-cell lymphoma (DLBCL) \u2014 relapsed or refractory, after two or more lines of systemic therapy; Follicular lymphoma (FL) \u2014 relapsed or refractory, after two or more lines of systemic therapy","ae":"CRS (51%), fatigue (26%), musculoskeletal pain (25%), injection site reactions (21%), infections (44%), abdominal pain (16%), nausea (15%), diarrhea (14%), pyrexia (11%), neutropenia (14%)","moa":"Epcoritamab is a subcutaneously administered bispecific IgG1 antibody that binds CD20 on B cells and CD3 on T cells. It engages T cells to kill CD20-positive tumor cells through directed T-cell cytotoxicity. The subcutaneous administration differentiates it from glofitamab (IV) and provides dosing convenience.","pk":"Half-life: approximately 19 days at 48 mg target dose. Non-linear PK during step-up doses. Steady-state by approximately Cycle 4. Clearance decreases with depletion of CD20-positive cells.","t":[]},{"s":"erbitux","b":"Erbitux","g":"cetuximab","c":"EGFR Inhibitor (Monoclonal Antibody)","a":"FDA Approved 2004","m":"Eli Lilly","i":"Head and neck squamous cell carcinoma \u2014 locally or regionally advanced (with radiation), recurrent locoregional or metastatic (with platinum-based therapy plus 5-FU, or as single agent after failure of platinum-based therapy); Metastatic colorectal cancer \u2014 KRAS wild-type (as determined by approved test), either with FOLFIRI (first-line), with irinotecan (after irinotecan failure), or as single agent (after failure of oxaliplatin- and irinotecan-based chemotherapy or in patients intolerant to ir","d":"Head and neck squamous cell carcinoma \u2014 locally or regionally advanced (with radiation), recurrent locoregional or metastatic (with platinum-based therapy plus 5-FU, or as single agent after failure of platinum-based therapy); Metastatic colorectal cancer \u2014 KRAS wild-type (as determined by approved test), either with FOLFIRI (first-line), with irinotecan (after irinotecan failure), or as single ag","ae":"Acneiform rash (76-88%), fatigue (49%), hypomagnesemia (55%), headache (26%), diarrhea (25%), infection (13-44%), nausea (29%), pyrexia (22%), nail changes (21%)","moa":"Cetuximab is a recombinant human/mouse chimeric IgG1 monoclonal antibody that binds specifically to the extracellular domain of the human epidermal growth factor receptor (EGFR/HER1/c-ErbB-1). It competitively inhibits EGF and other ligand binding, blocking receptor activation and downstream signaling (RAS/RAF/MAPK pathway). Cetuximab also mediates antibody-dependent cellular cytotoxicity (ADCC) a","pk":"Half-life: approximately 112 hours (range 63-230 hours). Vd: 2-3 L/m\u00b2. Clearance: 0.02 L/h/m\u00b2. Steady-state reached by third weekly infusion. Non-linear clearance at lower doses.","t":[{"name":"CRYSTAL","desc":"Cetuximab + FOLFIRI vs. FOLFIRI in 1L KRAS wild-type metastatic CRC. Phase III, n=1198."},{"name":"EXTREME","desc":"Cetuximab + platinum/5-FU vs. chemo in 1L recurrent/metastatic HNSCC. Phase III, n=442."}]},{"s":"erleada","b":"Erleada","g":"","c":"Androgen Receptor Inhibitor","a":"FDA Approved 2018","m":"Janssen","i":"Non-metastatic castration-resistant prostate cancer (nmCRPC); Metastatic castration-sensitive prostate cancer (mCSPC).","d":"Non-metastatic castration-resistant prostate cancer (nmCRPC); Metastatic castration-sensitive prostate cancer (mCSPC).","ae":"","moa":"","pk":"","t":[{"name":"SPARTAN","desc":"Apalutamide vs. placebo in non-metastatic CRPC. Phase III, n=1207."},{"name":"TITAN","desc":"Apalutamide + ADT vs. placebo + ADT in metastatic castration-sensitive prostate cancer. Phase III, n=1052."}]},{"s":"fotivda","b":"Fotivda","g":"tivozanib","c":"VEGFR Inhibitor (TKI)","a":"","m":"","i":"Advanced renal cell carcinoma (RCC) \u2014 relapsed or refractory, after two or more prior systemic therapies","d":"Advanced renal cell carcinoma (RCC) \u2014 relapsed or refractory, after two or more prior systemic therapies","ae":"Fatigue (44%), hypertension (45%), diarrhea (31%), decreased appetite (28%), nausea (24%), dysphonia (22%), hypothyroidism (11%), cough (11%), stomatitis (11%), vomiting (10%)","moa":"Tivozanib is a potent and selective inhibitor of VEGFR-1, VEGFR-2, and VEGFR-3 at picomolar concentrations, with minimal off-target kinase activity. This selectivity for VEGFRs reduces off-target side effects seen with less selective multi-kinase inhibitors. By blocking VEGFR signaling, tivozanib inhibits tumor angiogenesis, vascular permeability, and tumor growth.","pk":"Tmax: 2-24 hours. Half-life: approximately 4.5 days. Protein binding: >99%. Metabolized by CYP3A4 and CYP1A1. Fecal excretion (79%), urinary excretion (12%).","t":[{"name":"TIVO-3","desc":"Tivozanib vs. sorafenib in relapsed/refractory advanced RCC. Phase III, n=350."}]},{"s":"gavreto","b":"Gavreto","g":"pralsetinib","c":"RET Kinase Inhibitor","a":"FDA Approved 2020","m":"Genentech","i":"Non-small cell lung cancer \u2014 RET gene fusion-positive, metastatic, as detected by an FDA-approved test","d":"Non-small cell lung cancer \u2014 RET gene fusion-positive, metastatic, as detected by an FDA-approved test","ae":"Fatigue (35%), constipation (35%), musculoskeletal pain (32%), hypertension (29%), diarrhea (24%), edema (21%), cough (19%), abdominal pain (17%), dyspnea (16%), AST increase (42%), ALT increase (39%), decreased lymphocytes (52%), decreased neutrophils (44%)","moa":"Pralsetinib is a kinase inhibitor targeting wild-type RET and oncogenic RET fusions and mutations, including V804L/M gatekeeper mutations. It inhibits RET phosphorylation and downstream signaling pathways including MAPK and PI3K/AKT, blocking tumor cell proliferation.","pk":"Tmax: 2-4 hours. Half-life: approximately 14.7 hours. Protein binding: 97.1%. Metabolized primarily by CYP3A4. Fecal excretion (73%), urinary excretion (6%).","t":[{"name":"ARROW","desc":"Pralsetinib in RET fusion-positive NSCLC and RET-altered thyroid cancer. Phase I/II, n=438."}]},{"s":"gazyvaro","b":"Gazyvaro","g":"obinutuzumab","c":"","a":"","m":"","i":"Chronic lymphocytic leukemia (CLL) \u2014 previously untreated, in combination with chlorambucil; Follicular lymphoma (FL) \u2014 in combination with bendamustine followed by obinutuzumab monotherapy for patients who relapsed after or are refractory to a rituximab-containing regimen; FL \u2014 in combination with chemotherapy (bendamustine, CVP, or CHOP) followed by obinutuzumab monotherapy in previously untreated Stage II bulky, III, or IV patients who achieve at least a partial remission.","d":"Chronic lymphocytic leukemia (CLL) \u2014 previously untreated, in combination with chlorambucil; Follicular lymphoma (FL) \u2014 in combination with bendamustine followed by obinutuzumab monotherapy for patients who relapsed after or are refractory to a rituximab-containing regimen; FL \u2014 in combination with chemotherapy (bendamustine, CVP, or CHOP) followed by obinutuzumab monotherapy in previously untreat","ae":"Infusion-related reactions (69%), neutropenia (40%), thrombocytopenia (15%), nausea (37%), pyrexia (18%), cough (17%), diarrhea (17%), musculoskeletal pain (17%), fatigue (14%), constipation (12%), upper respiratory tract infection (11%)","moa":"Obinutuzumab is a humanized, glycoengineered Type II anti-CD20 monoclonal antibody. The Fc portion is glycoengineered with a non-fucosylated carbohydrate, which results in enhanced binding to Fc\u03b3RIIIa on immune effector cells. Compared to Type I anti-CD20 antibodies (rituximab), obinutuzumab induces greater direct cell death via a non-apoptotic lysosome-dependent mechanism, enhanced antibody-depen","pk":"Half-life: approximately 28 days (after 1000 mg dose). Clearance decreases over time as CD20-positive B cells are depleted. Vd: approximately 3.8 L. Steady-state reached during Cycle 3 of treatment.","t":[{"name":"CLL11","desc":"Obinutuzumab + chlorambucil vs. rituximab + chlorambucil vs. chlorambucil in 1L CLL. Phase III, n=781."}]},{"s":"gleevec","b":"Gleevec","g":"","c":"BCR-ABL Tyrosine Kinase Inhibitor","a":"FDA Approved 2001","m":"Novartis","i":"Newly diagnosed adult and pediatric Philadelphia chromosome-positive (Ph+) chronic myeloid leukemia (CML) in chronic phase; Ph+ CML in blast crisis, accelerated phase, or chronic phase after failure of interferon-alpha therapy; Ph+ acute lymphoblastic leukemia (ALL); Myelodysplastic/myeloproliferative diseases with PDGFR gene rearrangements; Aggressive systemic mastocytosis without D816V c-Kit mutation; Hypereosinophilic syndrome and/or chronic eosinophilic leukemia with FIP1L1-PDGFR\u03b1 fusion kin","d":"Newly diagnosed adult and pediatric Philadelphia chromosome-positive (Ph+) chronic myeloid leukemia (CML) in chronic phase; Ph+ CML in blast crisis, accelerated phase, or chronic phase after failure of interferon-alpha therapy; Ph+ acute lymphoblastic leukemia (ALL); Myelodysplastic/myeloproliferative diseases with PDGFR gene rearrangements; Aggressive systemic mastocytosis without D816V c-Kit mut","ae":"","moa":"","pk":"","t":[{"name":"IRIS","desc":"Imatinib vs. interferon-\u03b1 + cytarabine in newly diagnosed CML. Phase III, n=1106."}]},{"s":"gliadel-wafer","b":"Gliadel Wafer","g":"carmustine implant","c":"Nitrosourea Alkylating Agent (Implant)","a":"FDA Approved 1996","m":"Arbor Pharmaceuticals","i":"Newly diagnosed high-grade malignant glioma \u2014 as an adjunct to surgery and radiation; Recurrent glioblastoma multiforme \u2014 as an adjunct to surgery in patients for whom surgical resection is indicated.","d":"Newly diagnosed high-grade malignant glioma \u2014 as an adjunct to surgery and radiation; Recurrent glioblastoma multiforme \u2014 as an adjunct to surgery in patients for whom surgical resection is indicated.","ae":"Seizures (37%), brain edema (23%), hemiplegia (19%), headache (15%), healing abnormalities (14%), nausea (12%), infection (5-9%), confusion (10%), CSF leak (5%), fever (18%)","moa":"Gliadel wafers provide local, sustained release of carmustine (BCNU) directly into the tumor resection cavity. Carmustine is a nitrosourea alkylating agent that alkylates DNA at the O6-position of guanine, forming interstrand cross-links that inhibit DNA replication and transcription. The biodegradable polifeprosan 20 (poly[bis(p-carboxyphenoxy)propane:sebacic acid] 20:80) copolymer matrix slowly ","pk":"Wafer dissolves over 2-3 weeks in the resection cavity. Carmustine concentrations in brain tissue surrounding the wafers are much higher than achievable by IV administration. Systemic exposure is minimal. The biodegradable polymer is eliminated by hydrolysis over approximately 6-8 weeks.","t":[]},{"s":"halaven","b":"Halaven","g":"","c":"Microtubule Dynamics Inhibitor","a":"FDA Approved 2010","m":"Eisai","i":"Metastatic breast cancer \u2014 in patients who have previously received at least two chemotherapeutic regimens for metastatic disease (prior therapy should include an anthracycline and a taxane); Unresectable or metastatic liposarcoma \u2014 in patients who have received a prior anthracycline-containing regimen.","d":"Metastatic breast cancer \u2014 in patients who have previously received at least two chemotherapeutic regimens for metastatic disease (prior therapy should include an anthracycline and a taxane); Unresectable or metastatic liposarcoma \u2014 in patients who have received a prior anthracycline-containing regimen.","ae":"","moa":"","pk":"","t":[{"name":"EMBRACE","desc":"Eribulin vs. physician's choice in pretreated metastatic breast cancer. Phase III, n=762."}]},{"s":"herceptin","b":"Herceptin","g":"trastuzumab","c":"","a":"FDA Approved 1998","m":"Genentech","i":"HER2-overexpressing adjuvant breast cancer (as part of regimens containing doxorubicin, cyclophosphamide, and paclitaxel or docetaxel; with docetaxel and carboplatin; or as single agent following multi-modality anthracycline-based therapy); HER2-overexpressing metastatic breast cancer (with paclitaxel for first-line, or as single agent for \u22652 prior chemo regimens); HER2-overexpressing metastatic gastric or GEJ adenocarcinoma (with cisplatin and capecitabine or 5-FU, first-line)","d":"HER2-overexpressing adjuvant breast cancer (as part of regimens containing doxorubicin, cyclophosphamide, and paclitaxel or docetaxel; with docetaxel and carboplatin; or as single agent following multi-modality anthracycline-based therapy); HER2-overexpressing metastatic breast cancer (with paclitaxel for first-line, or as single agent for \u22652 prior chemo regimens); HER2-overexpressing metastatic g","ae":"","moa":"Trastuzumab is a recombinant humanized IgG1 monoclonal antibody that selectively binds to the extracellular domain of HER2 (ErbB2). It inhibits HER2-mediated signaling, mediates antibody-dependent cellular cytotoxicity (ADCC), and inhibits proliferation of tumor cells that overexpress HER2.","pk":"Half-life: dose-dependent; mean 28.5 days at maintenance doses. Vd: 44 mL/kg. Clearance: 5.15 mL/kg/day (decreased over time). Steady-state by ~20 weeks with weekly dosing, ~16 weeks with q3w. Mean washout time: ~7 months.","t":[{"name":"HERA","desc":"Trastuzumab after adjuvant chemotherapy in HER2+ early breast cancer. Phase III, n=5102."}]},{"s":"ibrance","b":"Ibrance","g":"palbociclib","c":"CDK4/6 Inhibitor","a":"FDA Approved 2015","m":"Pfizer","i":"HR+/HER2\u2212 Advanced or Metastatic Breast Cancer: In combination with an aromatase inhibitor as initial endocrine-based therapy in postmenopausal women or men. HR+/HER2\u2212 Advanced or Metastatic Breast Cancer: In combination with fulvestrant in patients with disease progression following endocrine therapy. PIK3CA-mutated Breast Cancer: In combination with inavolisib and fulvestrant for endocrine-resistant, PIK3CA-mutated, HR+/HER2\u2212 locally advanced or metastatic breast cancer following recurrence on","d":"HR+/HER2\u2212 Advanced or Metastatic Breast Cancer: In combination with an aromatase inhibitor as initial endocrine-based therapy in postmenopausal women or men. HR+/HER2\u2212 Advanced or Metastatic Breast Cancer: In combination with fulvestrant in patients with disease progression following endocrine therapy. PIK3CA-mutated Breast Cancer: In combination with inavolisib and fulvestrant for endocrine-resis","ae":"","moa":"Palbociclib is a selective inhibitor of cyclin-dependent kinases 4 and 6 (CDK4 and CDK6). CDK4/6 are downstream of multiple signaling pathways involved in cell proliferation. Palbociclib reduces cellular proliferation of ER-positive breast cancer cell lines by blocking progression of the cell from G1 into the S phase of the cell cycle. Combining palbociclib with anti-estrogen therapy leads to incr","pk":"Tmax: 4\u201312 hours. Bioavailability: 46% (125 mg dose). Steady state within 8 days; accumulation ratio 2.4. Vd: 2583 L. Protein binding: ~85%. Metabolized primarily by CYP3A and SULT2A1. Half-life: 29 hours (\u00b15). Elimination: feces 74%, urine 18%.","t":[{"name":"PALOMA-2","desc":"Palbociclib + letrozole vs. placebo + letrozole in first-line ER+/HER2\u2212 advanced breast cancer. Phase III, n=666."},{"name":"PALOMA-3","desc":"Palbociclib + fulvestrant vs. placebo + fulvestrant in HR+/HER2\u2212 advanced breast cancer after prior endocrine therapy. Phase III, n=521."}]},{"s":"iclusig","b":"Iclusig","g":"ponatinib","c":"BCR-ABL Tyrosine Kinase Inhibitor","a":"FDA Approved 2012","m":"Takeda","i":"Chronic myeloid leukemia (CML) \u2014 chronic, accelerated, or blast phase resistant to or intolerant of at least two prior kinase inhibitors; Philadelphia chromosome-positive acute lymphoblastic leukemia (Ph+ ALL) \u2014 resistant to or intolerant of at least two prior kinase inhibitors; CML or Ph+ ALL with T315I mutation","d":"Chronic myeloid leukemia (CML) \u2014 chronic, accelerated, or blast phase resistant to or intolerant of at least two prior kinase inhibitors; Philadelphia chromosome-positive acute lymphoblastic leukemia (Ph+ ALL) \u2014 resistant to or intolerant of at least two prior kinase inhibitors; CML or Ph+ ALL with T315I mutation","ae":"Hypertension (68%), rash (44%), abdominal pain (42%), fatigue (39%), headache (37%), dry skin (32%), constipation (37%), arthralgia (31%), nausea (29%), pyrexia (25%), thrombocytopenia (40%), myalgia (22%), pain in extremity (20%)","moa":"Ponatinib is a kinase inhibitor designed to be active against native and mutant BCR-ABL, including the T315I gatekeeper mutation that confers resistance to all other approved BCR-ABL inhibitors. Ponatinib also inhibits VEGFR, PDGFR, FGFR, EPH receptors, and SRC family kinases, and KIT, RET, TIE2, and FLT3.","pk":"Tmax: \u22646 hours. Half-life: approximately 24 hours. Protein binding: >99%. Metabolized by CYP3A4 and to a lesser extent CYP2C8 and CYP2D6. Fecal excretion (87%), urinary excretion (5%).","t":[{"name":"PACE","desc":"Ponatinib in resistant/intolerant CML and Ph+ ALL. Phase II, n=449."}]},{"s":"idhifa","b":"Idhifa","g":"enasidenib","c":"IDH2 Inhibitor","a":"FDA Approved 2017","m":"Bristol-Myers Squibb (Celgene/Agios)","i":"Acute myeloid leukemia (AML) \u2014 relapsed or refractory, with an IDH2 mutation as detected by an FDA-approved test","d":"Acute myeloid leukemia (AML) \u2014 relapsed or refractory, with an IDH2 mutation as detected by an FDA-approved test","ae":"Nausea (50%), total bilirubin increase (81%), indirect bilirubin increase (67%), diarrhea (43%), decreased appetite (34%), vomiting (34%), fatigue (28%), differentiation syndrome (14%), decreased calcium (24%), decreased potassium (17%)","moa":"Enasidenib is a small-molecule inhibitor of mutant isocitrate dehydrogenase 2 (IDH2) enzyme. Susceptible IDH2 mutations (R140Q, R172K, R172S, R172G) produce the oncometabolite D-2-hydroxyglutarate (2-HG) at elevated levels, causing epigenetic dysregulation and a block in cellular differentiation. Enasidenib inhibits the mutant IDH2 enzyme, reducing 2-HG levels and restoring myeloid differentiation","pk":"Tmax: 4 hours. Half-life: approximately 137 hours (terminal). Protein binding: 98.5%. Metabolized primarily by CYP enzymes (multiple). Fecal excretion (89%), urinary excretion (11%).","t":[]},{"s":"imbruvica","b":"Imbruvica","g":"ibrutinib","c":"","a":"FDA Approved 2013","m":"Pharmacyclics/Janssen","i":"Chronic lymphocytic leukemia (CLL)/Small lymphocytic lymphoma (SLL); Mantle cell lymphoma (MCL) after at least one prior therapy; Waldenstr\u00f6m's macroglobulinemia (WM); Marginal zone lymphoma (MZL) requiring systemic therapy after at least one prior anti-CD20-based therapy; Chronic graft-versus-host disease (cGVHD) after failure of one or more lines of systemic therapy","d":"Chronic lymphocytic leukemia (CLL)/Small lymphocytic lymphoma (SLL); Mantle cell lymphoma (MCL) after at least one prior therapy; Waldenstr\u00f6m's macroglobulinemia (WM); Marginal zone lymphoma (MZL) requiring systemic therapy after at least one prior anti-CD20-based therapy; Chronic graft-versus-host disease (cGVHD) after failure of one or more lines of systemic therapy","ae":"Diarrhea (43%), fatigue (28%), musculoskeletal pain (27%), rash (25%), bruising (23%), nausea (21%), hemorrhage (21%), hypertension (19%), upper respiratory tract infection (17%), arthralgia (13%)","moa":"Ibrutinib is a small-molecule inhibitor of Bruton's tyrosine kinase (BTK). It forms a covalent bond with cysteine 481 in the active site of BTK, inhibiting B-cell receptor signaling, disrupting B-cell adhesion, migration, and homing, and reducing malignant B-cell survival and proliferation.","pk":"Median Tmax: 1-2 hours. Half-life: 4-6 hours. Extensively metabolized by CYP3A. Clearance: 1000 L/h. Primarily excreted in feces (80%) and urine (10%).","t":[{"name":"RESONATE","desc":"Ibrutinib vs. ofatumumab in relapsed/refractory CLL. Phase III, n=391."},{"name":"RESONATE-2","desc":"Ibrutinib vs. chlorambucil in treatment-na\u00efve CLL (\u226565 years). Phase III, n=269."}]},{"s":"imdelltra","b":"Imdelltra","g":"tarlatamab-dlle","c":"Bispecific T-cell Engager (BiTE) \u2014 DLL3/CD3","a":"FDA Approved 2024","m":"Amgen","i":"Extensive-stage small cell lung cancer (ES-SCLC) in adults with disease progression on or after platinum-based chemotherapy.","d":"Extensive-stage small cell lung cancer (ES-SCLC) in adults with disease progression on or after platinum-based chemotherapy.","ae":"Cytokine release syndrome (53%), fatigue (41%), pyrexia (35%), dysgeusia (26%), constipation (25%), decreased appetite (23%), musculoskeletal pain (22%), nausea (21%), anemia (18%), rash (16%), lymphopenia (14%), hypotension (14%)","moa":"Tarlatamab is a bispecific T-cell engager (BiTE) antibody construct that binds simultaneously to DLL3 (delta-like ligand 3) on tumor cells and CD3 on T cells. DLL3 is an inhibitory Notch ligand that is aberrantly expressed on the surface of SCLC cells but has minimal expression on normal adult tissues. By bridging DLL3-positive tumor cells with cytotoxic T cells, tarlatamab activates T cells to re","pk":"Half-life: approximately 13-18 days at 10 mg dose. Steady-state reached by approximately Cycle 4. Non-linear pharmacokinetics at lower doses with target-mediated drug disposition. Volume of distribution approximately 4-5 L.","t":[]},{"s":"imfinzi","b":"Imfinzi","g":"durvalumab","c":"","a":"","m":"","i":"Unresectable Stage III NSCLC (after concurrent chemoradiation, PACIFIC setting); Extensive-stage small cell lung cancer (first-line, with etoposide and carboplatin/cisplatin); Biliary tract cancer (with gemcitabine and cisplatin, first-line); Hepatocellular carcinoma (with tremelimumab); Endometrial carcinoma","d":"Unresectable Stage III NSCLC (after concurrent chemoradiation, PACIFIC setting); Extensive-stage small cell lung cancer (first-line, with etoposide and carboplatin/cisplatin); Biliary tract cancer (with gemcitabine and cisplatin, first-line); Hepatocellular carcinoma (with tremelimumab); Endometrial carcinoma","ae":"","moa":"Durvalumab is a human IgG1 kappa monoclonal antibody that binds to PD-L1 and blocks PD-L1 binding to PD-1 and CD80 (B7.1), countering PD-L1-mediated inhibition of immune responses and enhancing T-cell-mediated anti-tumor activity.","pk":"Half-life: approximately 18 days. Clearance: 8.2 mL/h. Vd: 5.6 L. Steady-state by ~16 weeks. Linear PK at doses \u22653 mg/kg q2w. Not significantly affected by age, weight, gender, or mild-moderate renal impairment.","t":[{"name":"PACIFIC","desc":"Durvalumab vs. placebo after chemoradiation in unresectable stage III NSCLC. Phase III, n=713."},{"name":"HIMALAYA","desc":"Durvalumab \u00b1 tremelimumab vs. sorafenib in 1L unresectable HCC. Phase III, n=1171."}]},{"s":"imlygic","b":"Imlygic","g":"","c":"Oncolytic Viral Therapy (HSV-1 Based)","a":"FDA Approved 2015","m":"Amgen","i":"Unresectable cutaneous, subcutaneous, and nodal lesions in patients with melanoma recurrent after initial surgery.","d":"Unresectable cutaneous, subcutaneous, and nodal lesions in patients with melanoma recurrent after initial surgery.","ae":"","moa":"","pk":"","t":[]},{"s":"inlyta","b":"Inlyta","g":"axitinib","c":"VEGFR Inhibitor (TKI)","a":"","m":"","i":"Advanced renal cell carcinoma (RCC) after failure of one prior systemic therapy; Advanced RCC in combination with avelumab (first-line); Advanced RCC in combination with pembrolizumab (first-line)","d":"Advanced renal cell carcinoma (RCC) after failure of one prior systemic therapy; Advanced RCC in combination with avelumab (first-line); Advanced RCC in combination with pembrolizumab (first-line)","ae":"Diarrhea (55%), hypertension (40%), fatigue (39%), decreased appetite (34%), nausea (32%), dysphonia (31%), hand-foot syndrome (27%), weight decreased (25%), vomiting (24%), asthenia (21%), hypothyroidism (19%)","moa":"Axitinib is a potent and selective inhibitor of vascular endothelial growth factor receptors (VEGFR-1, VEGFR-2, VEGFR-3) at sub-nanomolar concentrations. These receptors mediate angiogenesis, vascular permeability, and lymphatic vessel formation. By blocking VEGFR signaling, axitinib inhibits tumor angiogenesis and growth.","pk":"Tmax: 2.5-4.1 hours. Half-life: 2.5-6.1 hours. Protein binding: >99%. Metabolized primarily by CYP3A4/5 and to a lesser extent CYP1A2, CYP2C19, UGT1A1. Fecal excretion (41%), urinary excretion (23%).","t":[{"name":"AXIS","desc":"Axitinib vs. sorafenib in previously treated advanced RCC. Phase III, n=723."}]},{"s":"jaypirca","b":"Jaypirca","g":"pirtobrutinib","c":"Non-Covalent (Reversible) BTK Inhibitor","a":"FDA Approved 2023","m":"Eli Lilly","i":"Mantle cell lymphoma (MCL) \u2014 relapsed or refractory after at least two lines of systemic therapy, including a BTK inhibitor; Chronic lymphocytic leukemia (CLL) or small lymphocytic lymphoma (SLL) \u2014 in adults who have received at least two prior lines of therapy, including a BTK inhibitor and a BCL-2 inhibitor","d":"Mantle cell lymphoma (MCL) \u2014 relapsed or refractory after at least two lines of systemic therapy, including a BTK inhibitor; Chronic lymphocytic leukemia (CLL) or small lymphocytic lymphoma (SLL) \u2014 in adults who have received at least two prior lines of therapy, including a BTK inhibitor and a BCL-2 inhibitor","ae":"Fatigue (36%), musculoskeletal pain (27%), diarrhea (22%), edema (22%), neutropenia (22%), dyspnea (15%), pneumonia (15%), bruising (14%), rash (13%), hemorrhage (12%), abdominal pain (11%)","moa":"Pirtobrutinib is a highly selective, non-covalent (reversible) inhibitor of Bruton's tyrosine kinase (BTK). Unlike covalent BTK inhibitors (ibrutinib, acalabrutinib, zanubrutinib) that bind irreversibly to C481, pirtobrutinib inhibits both wild-type BTK and C481S-mutant BTK through reversible binding. This allows it to maintain activity against tumors harboring the C481S resistance mutation that e","pk":"Tmax: 1-2 hours. Half-life: approximately 19 hours. Protein binding: 96%. Metabolized by CYP3A4. Steady-state by Day 8 with once-daily dosing. Excreted in feces (57%) and urine (23%).","t":[{"name":"BRUIN","desc":"Pirtobrutinib in relapsed/refractory B-cell malignancies including CLL after prior BTK inhibitor. Phase I/II."}]},{"s":"jemperli","b":"Jemperli","g":"dostarlimab-gxly","c":"PD-1 Inhibitor","a":"FDA Approved 2021","m":"GSK","i":"Endometrial cancer \u2014 mismatch repair deficient (dMMR) recurrent or advanced, as single agent after progression on or after prior platinum-containing regimen; Primary advanced or recurrent endometrial cancer \u2014 with carboplatin and paclitaxel, followed by single-agent dostarlimab (regardless of MMR status); dMMR recurrent or advanced solid tumors \u2014 as single agent after progression on or after prior treatment with no satisfactory alternative treatment options","d":"Endometrial cancer \u2014 mismatch repair deficient (dMMR) recurrent or advanced, as single agent after progression on or after prior platinum-containing regimen; Primary advanced or recurrent endometrial cancer \u2014 with carboplatin and paclitaxel, followed by single-agent dostarlimab (regardless of MMR status); dMMR recurrent or advanced solid tumors \u2014 as single agent after progression on or after prior","ae":"Fatigue/asthenia (42%), nausea (30%), diarrhea (26%), anemia (24%), constipation (18%), rash (14%), vomiting (14%), arthralgia (12%), pruritus (10%), hypothyroidism (7.5%)","moa":"Dostarlimab is a humanized IgG4 monoclonal antibody that binds to PD-1 and blocks its interaction with PD-L1 and PD-L2, thereby releasing PD-1-mediated inhibition of the immune response, including the anti-tumor immune response.","pk":"Half-life: approximately 25.4 days. Clearance: 0.0078 L/h. Vd: 5.4 L. Steady-state reached by approximately 4 months. Linear PK in dose range evaluated.","t":[{"name":"GARNET","desc":"Dostarlimab in dMMR/MSI-H endometrial cancer and other solid tumors. Phase I, n=515."}]},{"s":"jevtana","b":"Jevtana","g":"","c":"Taxane (Semi-synthetic)","a":"FDA Approved 2010","m":"Sanofi","i":"Metastatic castration-resistant prostate cancer (mCRPC) \u2014 in combination with prednisone, in patients previously treated with a docetaxel-containing regimen.","d":"Metastatic castration-resistant prostate cancer (mCRPC) \u2014 in combination with prednisone, in patients previously treated with a docetaxel-containing regimen.","ae":"","moa":"","pk":"","t":[{"name":"TROPIC","desc":"Cabazitaxel + prednisone vs. mitoxantrone + prednisone in mCRPC after docetaxel. Phase III, n=755."}]},{"s":"kadcyla","b":"Kadcyla","g":"ado-trastuzumab emtansine","c":"ADC (Anti-HER2)","a":"FDA Approved 2013","m":"Genentech/Roche","i":"Adjuvant HER2+ Breast Cancer: Single agent for adjuvant treatment of patients with HER2-positive early breast cancer who have residual invasive disease after neoadjuvant taxane and trastuzumab-based treatment. Metastatic HER2+ Breast Cancer: Single agent for treatment of patients with HER2-positive metastatic breast cancer who previously received trastuzumab and a taxane, separately or in combination.","d":"Adjuvant HER2+ Breast Cancer: Single agent for adjuvant treatment of patients with HER2-positive early breast cancer who have residual invasive disease after neoadjuvant taxane and trastuzumab-based treatment. Metastatic HER2+ Breast Cancer: Single agent for treatment of patients with HER2-positive metastatic breast cancer who previously received trastuzumab and a taxane, separately or in combinat","ae":"","moa":"Ado-trastuzumab emtansine is an antibody-drug conjugate containing the anti-HER2 humanized IgG1 monoclonal antibody trastuzumab covalently linked to the microtubule inhibitory drug DM1 (derivative of maytansine) via a stable thioether linker (MCC). Upon binding to HER2 on tumor cells, the ADC undergoes receptor-mediated internalization and lysosomal degradation, resulting in intracellular release ","pk":"Tmax: end of infusion. ADC Half-life: ~4 days. Vd: 3.13 L. Steady state by Cycle 1. DM1 metabolized by CYP3A4/5. Elimination primarily via catabolism. Minimal urinary excretion.","t":[{"name":"EMILIA","desc":"T-DM1 vs. lapatinib + capecitabine in HER2+ metastatic breast cancer after trastuzumab + taxane. Phase III, n=991."},{"name":"KATHERINE","desc":"Adjuvant T-DM1 vs. trastuzumab in HER2+ early breast cancer with residual disease after neoadjuvant therapy. Phase III, n=1486."}]},{"s":"keytruda","b":"Keytruda","g":"pembrolizumab","c":"PD-1 Inhibitor","a":"FDA Approved 2014","m":"Merck & Co.","i":"Melanoma (adjuvant and unresectable/metastatic); Non-small cell lung cancer (NSCLC) \u2014 first-line monotherapy (PD-L1 TPS \u22651%), first-line combination with chemo, after progression on platinum chemo; Small cell lung cancer; Head and neck squamous cell carcinoma; Classical Hodgkin lymphoma; Primary mediastinal large B-cell lymphoma; Urothelial carcinoma; Microsatellite instability-high (MSI-H) or mismatch repair deficient (dMMR) solid tumors; Gastric/GEJ adenocarcinoma; Esophageal cancer; Cervical ","d":"Melanoma (adjuvant and unresectable/metastatic); Non-small cell lung cancer (NSCLC) \u2014 first-line monotherapy (PD-L1 TPS \u22651%), first-line combination with chemo, after progression on platinum chemo; Small cell lung cancer; Head and neck squamous cell carcinoma; Classical Hodgkin lymphoma; Primary mediastinal large B-cell lymphoma; Urothelial carcinoma; Microsatellite instability-high (MSI-H) or mis","ae":"","moa":"Pembrolizumab is a humanized monoclonal antibody that binds to the programmed death-1 (PD-1) receptor on T cells, blocking its interaction with ligands PD-L1 and PD-L2. This releases PD-1 pathway-mediated inhibition of the immune response, including the anti-tumor immune response, thereby restoring T-cell-mediated killing of tumor cells.","pk":"Steady-state concentration reached by 16 weeks with repeated dosing every 3 weeks. Terminal half-life: approximately 22 days. Volume of distribution: 6.0 L. Clearance: 0.22 L/day.","t":[{"name":"KEYNOTE-024","desc":"Pembrolizumab vs. chemotherapy in 1L metastatic NSCLC with PD-L1 TPS \u226550%. Phase III, n=305."},{"name":"KEYNOTE-042","desc":"Pembrolizumab vs. chemotherapy in 1L NSCLC with PD-L1 TPS \u22651%. Phase III, n=1274."},{"name":"KEYNOTE-189","desc":"Pembrolizumab + pemetrexed/platinum vs. placebo + chemo in 1L nonsquamous NSCLC. Phase III, n=616."},{"name":"KEYNOTE-407","desc":"Pembrolizumab + carboplatin/paclitaxel vs. placebo + chemo in 1L squamous NSCLC. Phase III, n=559."}]},{"s":"kimmtrak","b":"Kimmtrak","g":"tebentafusp-tebn","c":"Bispecific gp100 Peptide-HLA-directed CD3 T-cell Engager","a":"FDA Approved 2022","m":"Immunocore","i":"Uveal melanoma \u2014 HLA-A*02:01-positive adults with unresectable or metastatic disease","d":"Uveal melanoma \u2014 HLA-A*02:01-positive adults with unresectable or metastatic disease","ae":"CRS (89%), rash (83%), pyrexia (76%), pruritus (69%), fatigue (51%), nausea (45%), chills (43%), abdominal pain (33%), edema (30%), hypotension (29%), dry skin (26%), headache (24%), vomiting (24%)","moa":"Tebentafusp is a bispecific gp100 peptide-HLA-directed CD3 T-cell engager. It consists of a high-affinity T-cell receptor (TCR) fused to an anti-CD3 single-chain variable fragment (scFv). The TCR domain recognizes gp100\u2082\u2088\u2080\u208b\u2082\u2088\u2088 peptide presented by HLA-A*02:01 on tumor cells. The anti-CD3 domain engages T cells, forming a synapse between T cells and gp100-positive tumor cells, leading to T-cell act","pk":"Half-life: approximately 7-9 hours. Tmax: end of infusion. Clearance: 1.4 L/h. Vd: 9.6 L. Rapid distribution and elimination due to small bispecific format. Steady-state not typically achieved (weekly dosing with short t\u00bd).","t":[]},{"s":"kisqali","b":"Kisqali","g":"ribociclib","c":"CDK4/6 Inhibitor","a":"FDA Approved 2017","m":"Novartis","i":"HR+/HER2\u2212 Advanced or Metastatic Breast Cancer: In combination with an aromatase inhibitor as initial endocrine-based therapy in pre/perimenopausal or postmenopausal women and men. HR+/HER2\u2212 Advanced or Metastatic Breast Cancer: In combination with fulvestrant as initial endocrine-based therapy or following disease progression on endocrine therapy in postmenopausal women and men. HR+/HER2\u2212 Early Breast Cancer (adjuvant): In combination with an aromatase inhibitor in adult patients with high risk","d":"HR+/HER2\u2212 Advanced or Metastatic Breast Cancer: In combination with an aromatase inhibitor as initial endocrine-based therapy in pre/perimenopausal or postmenopausal women and men. HR+/HER2\u2212 Advanced or Metastatic Breast Cancer: In combination with fulvestrant as initial endocrine-based therapy or following disease progression on endocrine therapy in postmenopausal women and men. HR+/HER2\u2212 Early B","ae":"","moa":"Ribociclib is a selective inhibitor of cyclin-dependent kinases 4 and 6 (CDK4/6). These kinases are activated upon binding to D-cyclins and play a critical role in signaling pathways leading to cell cycle progression and cellular proliferation. The cyclin D-CDK4/6 complex regulates cell cycle progression through phosphorylation of the retinoblastoma protein (pRb). Ribociclib inhibits pRb phosphory","pk":"Tmax: 1\u20135 hours. Bioavailability: ~32%. Vd: 1090 L. Protein binding: 70%. Metabolized primarily by CYP3A4. Half-life: 32 hours. Steady state by Day 8. Elimination: feces 69%, urine 23%.","t":[{"name":"MONALEESA-2","desc":"Ribociclib + letrozole vs. placebo + letrozole as first-line in HR+/HER2\u2212 advanced breast cancer (postmenopausal). Phase III, n=668."},{"name":"MONALEESA-3","desc":"Ribociclib + fulvestrant vs. placebo + fulvestrant in HR+/HER2\u2212 advanced breast cancer (postmenopausal). Phase III, n=726."},{"name":"MONALEESA-7","desc":"Ribociclib + endocrine therapy vs. placebo + endocrine therapy in pre/perimenopausal HR+/HER2\u2212 advanced breast cancer. Phase III, n=672."},{"name":"NATALEE","desc":"Adjuvant ribociclib + NSAI vs. NSAI alone in HR+/HER2\u2212 early breast cancer. Phase III, n=5101."}]},{"s":"kymriah","b":"Kymriah","g":"tisagenlecleucel","c":"CAR T-Cell Therapy (CD19-targeted)","a":"FDA Approved 2017","m":"Novartis","i":"B-cell precursor acute lymphoblastic leukemia (ALL) \u2014 in patients up to 25 years of age with refractory disease, in second or later relapse, or relapse post-transplant; Large B-cell lymphoma \u2014 relapsed or refractory after two or more lines of systemic therapy (DLBCL NOS, high-grade B-cell lymphoma, DLBCL arising from FL); Follicular lymphoma (FL) \u2014 relapsed or refractory after two or more lines of systemic therapy","d":"B-cell precursor acute lymphoblastic leukemia (ALL) \u2014 in patients up to 25 years of age with refractory disease, in second or later relapse, or relapse post-transplant; Large B-cell lymphoma \u2014 relapsed or refractory after two or more lines of systemic therapy (DLBCL NOS, high-grade B-cell lymphoma, DLBCL arising from FL); Follicular lymphoma (FL) \u2014 relapsed or refractory after two or more lines of","ae":"CRS (57-79%), infections (34-48%), decreased appetite (24-33%), headache (25-37%), encephalopathy (17-34%), hypotension (20-26%), febrile neutropenia (14-35%), tachycardia (14-26%), fatigue (26-29%), nausea (21-26%)","moa":"Tisagenlecleucel is a CD19-directed genetically modified autologous T-cell immunotherapy. Patient T cells are transduced with a lentiviral vector encoding a CAR composed of an anti-CD19 scFv linked to 4-1BB (CD137) costimulatory and CD3-zeta signaling domains. The 4-1BB costimulatory domain enhances T-cell persistence and expansion. Upon binding CD19-positive cells, the CAR T cells activate and er","pk":"Peak CAR T-cell expansion: median 10 days (ALL), 9 days (DLBCL). Transgene detectable in blood for up to 2 years. Higher peak expansion correlated with response. 4-1BB costimulatory domain promotes long-term T-cell persistence.","t":[{"name":"ELIANA","desc":"Tisagenlecleucel in pediatric/young adult relapsed/refractory B-ALL. Phase II, n=75."},{"name":"JULIET","desc":"Tisagenlecleucel in relapsed/refractory DLBCL. Phase II, n=93."}]},{"s":"kyprolis","b":"Kyprolis","g":"carfilzomib","c":"Proteasome Inhibitor","a":"","m":"Amgen","i":"Multiple myeloma \u2014 in combination with dexamethasone or with lenalidomide plus dexamethasone, in patients who have received one to three prior lines of therapy; in combination with daratumumab, dexamethasone in patients who have received one to three prior lines of therapy","d":"Multiple myeloma \u2014 in combination with dexamethasone or with lenalidomide plus dexamethasone, in patients who have received one to three prior lines of therapy; in combination with daratumumab, dexamethasone in patients who have received one to three prior lines of therapy","ae":"Anemia (47%), fatigue (33%), thrombocytopenia (36%), nausea (32%), diarrhea (33%), dyspnea (28%), pyrexia (27%), upper respiratory tract infection (24%), headache (22%), hypertension (22%), cough (21%)","moa":"Carfilzomib is an irreversible proteasome inhibitor that selectively and irreversibly binds to the N-terminal threonine-containing active sites of the 20S proteasome (chymotrypsin-like activity). Unlike bortezomib which is reversible, carfilzomib's irreversible binding provides sustained proteasome inhibition. This leads to accumulation of polyubiquitinated proteins, activating the unfolded protei","pk":"Half-life: approximately 1 hour (on Day 1 of Cycle 1). Rapidly and extensively metabolized via peptidase cleavage and epoxide hydrolysis. Less than 1% excreted unchanged in urine. Clearance: 263 L/h.","t":[{"name":"ASPIRE","desc":"Carfilzomib + lenalidomide/dex vs. lenalidomide/dex in relapsed MM. Phase III, n=792."},{"name":"ENDEAVOR","desc":"Carfilzomib + dex vs. bortezomib + dex in relapsed MM. Phase III, n=929."}]},{"s":"lenvima","b":"Lenvima","g":"lenvatinib","c":"","a":"FDA Approved 2015","m":"Eisai","i":"Locally recurrent or metastatic, progressive, radioactive iodine-refractory differentiated thyroid cancer (DTC); First-line treatment of unresectable hepatocellular carcinoma (HCC); Advanced renal cell carcinoma (with pembrolizumab, first-line); Advanced endometrial carcinoma (with pembrolizumab, not MSI-H or dMMR, after prior systemic therapy)","d":"Locally recurrent or metastatic, progressive, radioactive iodine-refractory differentiated thyroid cancer (DTC); First-line treatment of unresectable hepatocellular carcinoma (HCC); Advanced renal cell carcinoma (with pembrolizumab, first-line); Advanced endometrial carcinoma (with pembrolizumab, not MSI-H or dMMR, after prior systemic therapy)","ae":"Hypertension (73%), diarrhea (67%), fatigue (59%), decreased appetite (54%), decreased weight (51%), nausea (47%), stomatitis (41%), vomiting (36%), proteinuria (34%), PPE (32%), abdominal pain (31%), dysphonia (31%)","moa":"Lenvatinib is a receptor tyrosine kinase inhibitor that inhibits VEGFR1-3, FGFR1-4, PDGFR\u03b1, KIT, and RET. It inhibits tumor angiogenesis through VEGFR and FGFR inhibition, suppresses tumor cell proliferation through RET and KIT inhibition, and modulates the tumor immune microenvironment.","pk":"Tmax: 1-4 hours. Half-life: approximately 28 hours. Protein binding: 98-99%. Metabolized by CYP3A and aldehyde oxidase. Excreted in feces (64%) and urine (25%).","t":[{"name":"SELECT","desc":"Lenvatinib vs. placebo in radioactive iodine-refractory differentiated thyroid cancer. Phase III, n=392."},{"name":"REFLECT","desc":"Lenvatinib vs. sorafenib in 1L unresectable HCC. Phase III, n=954."}]},{"s":"libtayo","b":"Libtayo","g":"cemiplimab-rwlc","c":"PD-1 Inhibitor","a":"FDA Approved 2018","m":"Regeneron/Sanofi","i":"Cutaneous squamous cell carcinoma (metastatic or locally advanced not candidate for curative surgery/radiation); Basal cell carcinoma (locally advanced or metastatic previously treated with hedgehog pathway inhibitor or for whom HHI is not appropriate); Non-small cell lung cancer (first-line, PD-L1 \u226550%, no EGFR/ALK/ROS1 aberrations); Cervical cancer (recurrent or metastatic with PD-L1 CPS \u22651, with chemo \u00b1 bevacizumab)","d":"Cutaneous squamous cell carcinoma (metastatic or locally advanced not candidate for curative surgery/radiation); Basal cell carcinoma (locally advanced or metastatic previously treated with hedgehog pathway inhibitor or for whom HHI is not appropriate); Non-small cell lung cancer (first-line, PD-L1 \u226550%, no EGFR/ALK/ROS1 aberrations); Cervical cancer (recurrent or metastatic with PD-L1 CPS \u22651, wit","ae":"","moa":"Cemiplimab is a human IgG4 monoclonal antibody that binds to PD-1 and blocks its interactions with PD-L1 and PD-L2, releasing PD-1 pathway-mediated inhibition of the anti-tumor immune response.","pk":"Half-life: 19.4 days. Clearance: 0.24 L/day. Vd: 5.2 L. Steady-state by ~4 months with q3w dosing. Linear PK across 1-10 mg/kg. Not significantly affected by age, body weight, or mild renal impairment.","t":[]},{"s":"loqtorzi","b":"Loqtorzi","g":"toripalimab-tpzi","c":"PD-1 Inhibitor","a":"FDA Approved 2023","m":"Coherus BioSciences/Junshi","i":"Nasopharyngeal carcinoma (NPC) \u2014 metastatic or recurrent locally advanced, in combination with cisplatin and gemcitabine as first-line treatment; NPC \u2014 recurrent unresectable or metastatic following prior platinum-containing chemotherapy, as single agent.","d":"Nasopharyngeal carcinoma (NPC) \u2014 metastatic or recurrent locally advanced, in combination with cisplatin and gemcitabine as first-line treatment; NPC \u2014 recurrent unresectable or metastatic following prior platinum-containing chemotherapy, as single agent.","ae":"Nausea (42%), fatigue (35%), decreased appetite (27%), constipation (24%), musculoskeletal pain (22%), anemia (21%), rash (18%), vomiting (17%), cough (16%), hypothyroidism (13%), diarrhea (13%)","moa":"Toripalimab is a humanized IgG4\u03ba monoclonal antibody that binds to PD-1 and blocks its interaction with PD-L1 and PD-L2. By preventing PD-1 pathway-mediated inhibition of the immune response, toripalimab restores T-cell-mediated anti-tumor activity. It was the first anti-PD-1 antibody approved for nasopharyngeal carcinoma in the US.","pk":"Half-life: approximately 17 days at 240 mg q3w. Steady-state achieved by Cycle 4. Clearance: 0.24 L/day. Volume of distribution: approximately 5.3 L.","t":[{"name":"JUPITER-02","desc":"Toripalimab + gemcitabine/cisplatin vs. placebo + chemo in 1L nasopharyngeal carcinoma. Phase III, n=289."}]},{"s":"lunsumio","b":"Lunsumio","g":"mosunetuzumab-axgb","c":"Bispecific Antibody (CD20/CD3)","a":"FDA Approved 2022","m":"Genentech/Roche","i":"Relapsed or refractory follicular lymphoma (FL) after two or more prior lines of systemic therapy.","d":"Relapsed or refractory follicular lymphoma (FL) after two or more prior lines of systemic therapy.","ae":"Cytokine release syndrome (39%), fatigue (25%), rash (20%), headache (18%), pyrexia (17%), diarrhea (15%), upper respiratory tract infection (14%), neutropenia (24%), hypophosphatemia (15%)","moa":"Mosunetuzumab is a bispecific antibody that bridges CD20-expressing B-cell lymphoma cells and CD3-expressing T cells. It binds CD20 on tumor cells and CD3\u03b5 on T cells simultaneously, forming an immunological synapse that activates T cells to release cytotoxic granules (perforin and granzymes), resulting in lysis of CD20-positive tumor cells. This mechanism is independent of T-cell receptor specifi","pk":"Half-life: approximately 16 days at 30 mg. Non-linear PK at lower doses due to target-mediated drug disposition. Steady-state approached by Cycle 3. Clearance decreases with repeated dosing as CD20+ B cells are depleted.","t":[{"name":"GO29781","desc":"Mosunetuzumab in relapsed/refractory follicular lymphoma after \u22652 prior therapies. Phase I/II."}]},{"s":"lurbinectedin","b":"Lurbinectedin","g":"lurbinectedin","c":"","a":"","m":"","i":"Small cell lung cancer (SCLC) \u2014 metastatic, with disease progression on or after platinum-based chemotherapy","d":"Small cell lung cancer (SCLC) \u2014 metastatic, with disease progression on or after platinum-based chemotherapy","ae":"Fatigue (47%), nausea (37%), decreased appetite (28%), musculoskeletal pain (26%), constipation (24%), dyspnea (20%), vomiting (18%), cough (14%), diarrhea (11%), anemia (93%), neutropenia (46%), leukopenia (40%), thrombocytopenia (40%), creatinine increase (42%), ALT increase (35%)","moa":"Lurbinectedin is a synthetic alkaloid analogue of trabectedin that covalently binds to the minor groove of DNA. It selectively inhibits oncogenic transcription by binding to CG-rich sequences near gene promoters, trapping RNA polymerase II complexes on DNA, and inducing their degradation. This leads to a cascade of events including DNA double-strand breaks and apoptosis. Lurbinectedin also modulat","pk":"Half-life: approximately 51 hours (terminal). Clearance: 17 L/h. Vd: 851 L (extensive tissue distribution). Protein binding: 99%. Metabolized primarily by CYP3A4. Excreted in feces (88%) and urine (6%).","t":[]},{"s":"lutathera","b":"Lutathera","g":"","c":"Peptide Receptor Radionuclide Therapy (PRRT)","a":"FDA Approved 2018","m":"Novartis","i":"Somatostatin receptor-positive gastroenteropancreatic neuroendocrine tumors (GEP-NETs), including foregut, midgut, and hindgut NETs, in adults.","d":"Somatostatin receptor-positive gastroenteropancreatic neuroendocrine tumors (GEP-NETs), including foregut, midgut, and hindgut NETs, in adults.","ae":"","moa":"","pk":"","t":[{"name":"NETTER-1","desc":"177Lu-DOTATATE + octreotide LAR vs. octreotide LAR alone in midgut NETs. Phase III, n=229."}]},{"s":"lynparza","b":"Lynparza","g":"olaparib","c":"PARP Inhibitor","a":"","m":"","i":"Ovarian cancer: First-line maintenance (with BRCA mutation or HRD-positive after platinum response, as monotherapy or with bevacizumab); Maintenance after \u22652 prior platinum-based regimens. Breast cancer: Adjuvant HER2-negative high-risk early breast cancer with germline BRCA mutation after chemo; Germline BRCA-mutated HER2-negative metastatic breast cancer. Pancreatic cancer: First-line maintenance with germline BRCA mutation after platinum response. Prostate cancer: HRR gene-mutated metastatic ","d":"Ovarian cancer: First-line maintenance (with BRCA mutation or HRD-positive after platinum response, as monotherapy or with bevacizumab); Maintenance after \u22652 prior platinum-based regimens. Breast cancer: Adjuvant HER2-negative high-risk early breast cancer with germline BRCA mutation after chemo; Germline BRCA-mutated HER2-negative metastatic breast cancer. Pancreatic cancer: First-line maintenanc","ae":"","moa":"Olaparib is an inhibitor of poly (ADP-ribose) polymerase (PARP) enzymes, including PARP-1, PARP-2, and PARP-3. PARP enzymes are involved in normal cellular functions including DNA repair. Olaparib-induced cytotoxicity involves inhibition of PARP enzymatic activity and trapping of PARP-DNA complexes, resulting in DNA damage, apoptosis, and cell death in cells with deficiencies in homologous recombi","pk":"Tmax: 1.5 hours. Half-life: 14.9 hours. Protein binding: 82%. Metabolized by CYP3A. Steady-state by Day 3-5. Excreted in urine (44%, 15% unchanged) and feces (42%, 6% unchanged). Dose reduce for CrCl 31-50 mL/min.","t":[{"name":"SOLO-1","desc":"Olaparib maintenance vs. placebo in 1L BRCA-mutated advanced ovarian cancer. Phase III, n=391."}]},{"s":"lytgobi","b":"Lytgobi","g":"futibatinib","c":"FGFR Inhibitor (Pan-FGFR, Irreversible)","a":"FDA Approved 2022","m":"Taiho Oncology","i":"Previously treated, unresectable, locally advanced, or metastatic intrahepatic cholangiocarcinoma harboring FGFR2 gene fusions or other rearrangements, as detected by an FDA-approved test.","d":"Previously treated, unresectable, locally advanced, or metastatic intrahepatic cholangiocarcinoma harboring FGFR2 gene fusions or other rearrangements, as detected by an FDA-approved test.","ae":"Hyperphosphatemia (85%), alopecia (33%), PPE/hand-foot syndrome (32%), diarrhea (28%), dry mouth (27%), fatigue (25%), stomatitis (25%), nail toxicity (22%), constipation (22%), dry skin (22%), decreased appetite (21%), nausea (21%), dysgeusia (19%), dry eye (18%)","moa":"Futibatinib is an irreversible, covalent pan-FGFR inhibitor that binds to a conserved cysteine residue (Cys492 in FGFR1) in the P-loop of FGFR1, FGFR2, FGFR3, and FGFR4. By forming a covalent bond, it achieves sustained kinase inhibition even after drug clearance. It inhibits FGFR phosphorylation and downstream FRS2/RAS/MAPK and PI3K/AKT signaling. The irreversible binding mechanism may overcome c","pk":"Tmax: 2-3 hours. Half-life: approximately 14 hours (terminal). Protein binding: ~98%. Metabolized by CYP3A4 and CYP2C9. Steady-state by Day 8. Excreted in feces (79%) and urine (6%).","t":[]},{"s":"mekinist","b":"Mekinist","g":"","c":"MEK Inhibitor","a":"FDA Approved 2013","m":"Novartis","i":"Used in combination with dabrafenib for all dabrafenib indications: unresectable/metastatic melanoma BRAF V600E/K, adjuvant melanoma BRAF V600E/K, metastatic NSCLC BRAF V600E, anaplastic thyroid BRAF V600E, BRAF V600E solid tumors, pediatric low-grade glioma BRAF V600E.","d":"Used in combination with dabrafenib for all dabrafenib indications: unresectable/metastatic melanoma BRAF V600E/K, adjuvant melanoma BRAF V600E/K, metastatic NSCLC BRAF V600E, anaplastic thyroid BRAF V600E, BRAF V600E solid tumors, pediatric low-grade glioma BRAF V600E.","ae":"","moa":"","pk":"","t":[]},{"s":"minjuvi","b":"Minjuvi","g":"tafasitamab-cxix","c":"","a":"","m":"","i":"Relapsed or refractory diffuse large B-cell lymphoma (DLBCL) not otherwise specified, including DLBCL arising from low-grade lymphoma, in combination with lenalidomide, in patients who are not eligible for autologous stem cell transplant (ASCT).","d":"Relapsed or refractory diffuse large B-cell lymphoma (DLBCL) not otherwise specified, including DLBCL arising from low-grade lymphoma, in combination with lenalidomide, in patients who are not eligible for autologous stem cell transplant (ASCT).","ae":"Neutropenia (51%), fatigue (38%), anemia (36%), diarrhea (36%), thrombocytopenia (31%), cough (26%), pyrexia (24%), peripheral edema (24%), upper respiratory tract infection (22%), decreased appetite (22%), hypokalemia (19%), back pain (19%), rash (18%)","moa":"Tafasitamab is a humanized anti-CD19 IgG1/2 hybrid monoclonal antibody with an Fc-engineered domain. The Fc modification (two amino acid substitutions: S239D and I332E) enhances binding to Fc\u03b3RIIIa on natural killer cells and macrophages, resulting in enhanced antibody-dependent cellular cytotoxicity (ADCC) and antibody-dependent cellular phagocytosis (ADCP) against CD19-positive lymphoma cells. I","pk":"Half-life: approximately 17 days. Steady-state achieved by Cycle 4. Clearance: approximately 0.007 L/h. Volume of distribution: approximately 9.3 L. Minimal non-linearity.","t":[]},{"s":"mylotarg","b":"Mylotarg","g":"gemtuzumab ozogamicin","c":"Antibody-Drug Conjugate (CD33-targeted)","a":"FDA Approved 2017","m":"Pfizer","i":"Acute myeloid leukemia (AML) \u2014 newly diagnosed CD33-positive AML in adults (in combination with daunorubicin and cytarabine); relapsed or refractory CD33-positive AML in adults and pediatric patients \u22651 month old","d":"Acute myeloid leukemia (AML) \u2014 newly diagnosed CD33-positive AML in adults (in combination with daunorubicin and cytarabine); relapsed or refractory CD33-positive AML in adults and pediatric patients \u22651 month old","ae":"Hemorrhage (99%), infection (84%), nausea (78%), fever (78%), thrombocytopenia (87%), anemia (52%), stomatitis (45%), constipation (42%), vomiting (40%), headache (35%), diarrhea (32%), rash (31%), elevated transaminases (24%), mucositis (18%)","moa":"Gemtuzumab ozogamicin is an antibody-drug conjugate comprising a humanized anti-CD33 IgG4 antibody linked to N-acetyl-gamma-calicheamicin dimethylhydrazide (calicheamicin) via an acid-labile linker. CD33 is expressed on the surface of leukemic blasts in >80% of AML patients. Upon binding CD33, the ADC is internalized, and calicheamicin is released in lysosomes, where it binds to DNA minor groove, ","pk":"Half-life: approximately 62-90 hours (unconjugated calicheamicin). Clearance decreases after first dose as CD33+ cells are depleted. Tmax: end of infusion. Payload (N-acetyl-gamma-calicheamicin) released after internalization and lysosomal processing.","t":[{"name":"ALFA-0701","desc":"Gemtuzumab ozogamicin + chemo vs. chemo in newly diagnosed CD33+ AML. Phase III, n=271."}]},{"s":"nexavar","b":"Nexavar","g":"sorafenib","c":"","a":"FDA Approved 2005","m":"Bayer","i":"Unresectable hepatocellular carcinoma (HCC); Advanced renal cell carcinoma (RCC); Locally recurrent or metastatic, progressive, differentiated thyroid carcinoma (DTC) refractory to radioactive iodine treatment","d":"Unresectable hepatocellular carcinoma (HCC); Advanced renal cell carcinoma (RCC); Locally recurrent or metastatic, progressive, differentiated thyroid carcinoma (DTC) refractory to radioactive iodine treatment","ae":"Diarrhea (43%), fatigue (37%), hand-foot skin reaction (30%), rash/desquamation (40%), alopecia (27%), nausea (23%), hypertension (17%), pruritus (14%), anorexia (16%)","moa":"Sorafenib is a kinase inhibitor that decreases tumor cell proliferation by inhibiting multiple intracellular (CRAF, BRAF, mutant BRAF) and cell surface kinases (KIT, FLT-3, RET, VEGFR-1, VEGFR-2, VEGFR-3, PDGFR-\u03b2). It inhibits tumor angiogenesis via VEGFR and PDGFR inhibition and direct anti-tumor activity via RAF/MEK/ERK pathway inhibition.","pk":"Tmax: approximately 3 hours. Half-life: 25-48 hours. Bioavailability: 38-49% (reduced by high-fat meals). Protein binding: 99.5%. Metabolized by CYP3A4 and UGT1A9. Primarily excreted in feces (77%).","t":[{"name":"SHARP","desc":"Sorafenib vs. placebo in advanced HCC. Phase III, n=602."},{"name":"TARGET","desc":"Sorafenib vs. placebo in advanced clear-cell RCC after prior therapy. Phase III, n=903."}]},{"s":"ninlaro","b":"Ninlaro","g":"ixazomib","c":"","a":"","m":"","i":"Multiple myeloma \u2014 in combination with lenalidomide and dexamethasone, for patients who have received at least one prior therapy","d":"Multiple myeloma \u2014 in combination with lenalidomide and dexamethasone, for patients who have received at least one prior therapy","ae":"Diarrhea (42%), constipation (34%), thrombocytopenia (78%), nausea (26%), peripheral neuropathy (28%), peripheral edema (25%), vomiting (22%), back pain (21%), rash (19%), upper respiratory tract infection (19%), decreased appetite (11%)","moa":"Ixazomib is an oral proteasome inhibitor that reversibly binds the beta 5 subunit of the 20S proteasome with high selectivity. It inhibits the chymotrypsin-like activity of the proteasome, leading to accumulation of polyubiquitinated proteins, activation of the unfolded protein response, cell cycle arrest, and apoptosis. As an oral agent, it offers a convenient alternative to IV proteasome inhibit","pk":"Tmax: 1 hour. Absolute bioavailability: 58%. Half-life: 9.5 days. Protein binding: 99%. Metabolized by multiple CYP enzymes and non-CYP proteins. Urinary excretion (62%), fecal excretion (22%).","t":[]},{"s":"nubeqa","b":"Nubeqa","g":"","c":"Androgen Receptor Inhibitor","a":"FDA Approved 2019","m":"Bayer","i":"Non-metastatic castration-resistant prostate cancer (nmCRPC); Metastatic hormone-sensitive prostate cancer (mHSPC) \u2014 in combination with docetaxel.","d":"Non-metastatic castration-resistant prostate cancer (nmCRPC); Metastatic hormone-sensitive prostate cancer (mHSPC) \u2014 in combination with docetaxel.","ae":"","moa":"","pk":"","t":[{"name":"ARAMIS","desc":"Darolutamide vs. placebo in non-metastatic CRPC. Phase III, n=1509."},{"name":"ARASENS","desc":"Darolutamide + docetaxel + ADT vs. placebo + docetaxel + ADT in mHSPC. Phase III, n=1306."}]},{"s":"onureg","b":"Onureg","g":"azacitidine tablets","c":"Nucleoside Metabolic Inhibitor (Oral Hypomethylating Agent)","a":"FDA Approved 2020","m":"Bristol-Myers Squibb","i":"Acute myeloid leukemia (AML) \u2014 continued treatment (maintenance) in adult patients who achieved first complete remission (CR) or complete remission with incomplete blood count recovery (CRi) following intensive induction chemotherapy and are not able to complete intensive curative therapy","d":"Acute myeloid leukemia (AML) \u2014 continued treatment (maintenance) in adult patients who achieved first complete remission (CR) or complete remission with incomplete blood count recovery (CRi) following intensive induction chemotherapy and are not able to complete intensive curative therapy","ae":"Nausea (65%), vomiting (60%), diarrhea (50%), fatigue (44%), constipation (39%), pneumonia (22%), abdominal pain (22%), arthralgia (14%), decreased appetite (13%), febrile neutropenia (12%), dizziness (11%)","moa":"Oral azacitidine is a nucleoside metabolic inhibitor. After cellular uptake and conversion to its active triphosphate form (decitabine triphosphate), it is incorporated into DNA, where it inhibits DNA methyltransferase (DNMT), leading to DNA hypomethylation. At low doses, this epigenetic modulation restores expression of silenced tumor suppressor genes, promoting cellular differentiation and apopt","pk":"Tmax: 1 hour. Half-life: approximately 0.5 hours (azacitidine oral rapidly degraded). Oral bioavailability ~11%. Not significantly metabolized by CYP enzymes; cleared by spontaneous hydrolysis and deamination by cytidine deaminase. Excreted primarily in urine.","t":[]},{"s":"opdivo","b":"Opdivo","g":"nivolumab","c":"PD-1 Inhibitor","a":"FDA Approved 2014","m":"Bristol-Myers Squibb","i":"Melanoma (adjuvant and unresectable/metastatic); Non-small cell lung cancer; Malignant pleural mesothelioma; Renal cell carcinoma; Classical Hodgkin lymphoma; Squamous cell carcinoma of the head and neck; Urothelial carcinoma; Microsatellite instability-high (MSI-H) or dMMR colorectal cancer; Hepatocellular carcinoma; Esophageal cancer; Gastric/GEJ/esophageal adenocarcinoma","d":"Melanoma (adjuvant and unresectable/metastatic); Non-small cell lung cancer; Malignant pleural mesothelioma; Renal cell carcinoma; Classical Hodgkin lymphoma; Squamous cell carcinoma of the head and neck; Urothelial carcinoma; Microsatellite instability-high (MSI-H) or dMMR colorectal cancer; Hepatocellular carcinoma; Esophageal cancer; Gastric/GEJ/esophageal adenocarcinoma","ae":"","moa":"Nivolumab is a human IgG4 monoclonal antibody that binds to the PD-1 receptor, blocking its interaction with PD-L1 and PD-L2 ligands, thereby releasing PD-1 pathway-mediated inhibition of the anti-tumor immune response.","pk":"Steady-state reached by 12 weeks. Terminal half-life: 26.7 days. Clearance: 9.5 mL/h. Volume of distribution at steady state: 8.0 L.","t":[]},{"s":"opdualag","b":"Opdualag","g":"","c":"PD-1/LAG-3 Inhibitor (Fixed-Dose Combination)","a":"FDA Approved 2022","m":"BMS","i":"Unresectable or metastatic melanoma in adults and pediatric patients 12 years of age or older weighing at least 40 kg.","d":"Unresectable or metastatic melanoma in adults and pediatric patients 12 years of age or older weighing at least 40 kg.","ae":"","moa":"","pk":"","t":[{"name":"RELATIVITY-047","desc":"Nivolumab + relatlimab vs. nivolumab alone in untreated advanced melanoma. Phase II/III, n=714."}]},{"s":"optune","b":"Optune","g":"tumor treating fields (TTFields)","c":"","a":"FDA Approved 2011","m":"Novocure","i":"Newly diagnosed glioblastoma (GBM) \u2014 in combination with temozolomide, after completion of maximal debulking surgery and concomitant chemoradiation; Recurrent glioblastoma \u2014 as a monotherapy in adult patients after surgical and radiation therapy options have been exhausted.","d":"Newly diagnosed glioblastoma (GBM) \u2014 in combination with temozolomide, after completion of maximal debulking surgery and concomitant chemoradiation; Recurrent glioblastoma \u2014 as a monotherapy in adult patients after surgical and radiation therapy options have been exhausted.","ae":"Skin irritation/dermatitis (43%), headache (14%), fatigue (9%), muscle twitching under arrays (4%), discomfort at array sites (common), electric sensation/tingling under arrays (common). No systemic adverse effects \u2014 device is local therapy.","moa":"Optune (TTFields) delivers low-intensity (1-3 V/cm), intermediate-frequency (200 kHz) alternating electric fields to the tumor region via transducer arrays on the scalp. TTFields exert anti-mitotic effects by two mechanisms: (1) During metaphase, the fields exert directional forces on polar molecules (especially tubulin), disrupting mitotic spindle assembly and preventing proper chromosome alignme","pk":"Not applicable \u2014 Optune is a medical device, not a pharmaceutical agent. TTFields are delivered continuously via transducer arrays on the scalp at 200 kHz, 1-3 V/cm. Electric field intensity is highest near the arrays and attenuates with depth. Computational modeling based on MRI-derived head models","t":[{"name":"EF-14","desc":"TTFields + temozolomide vs. temozolomide alone in newly diagnosed glioblastoma. Phase III, n=695."}]},{"s":"orgovyx","b":"Orgovyx","g":"","c":"GnRH Receptor Antagonist (Oral)","a":"FDA Approved 2020","m":"Myovant Sciences","i":"Advanced prostate cancer.","d":"Advanced prostate cancer.","ae":"","moa":"","pk":"","t":[{"name":"HERO","desc":"Relugolix vs. leuprolide in advanced prostate cancer. Phase III, n=930."}]},{"s":"padcev","b":"Padcev","g":"enfortumab vedotin-ejfv","c":"ADC (Anti-Nectin-4)","a":"FDA Approved 2019","m":"Astellas/Seagen","i":"First-line (with pembrolizumab): In combination with pembrolizumab for adult patients with locally advanced or metastatic urothelial cancer, regardless of cisplatin eligibility. Monotherapy: Adult patients with locally advanced or metastatic urothelial cancer who have previously received a PD-1/PD-L1 inhibitor and platinum-containing chemotherapy.","d":"First-line (with pembrolizumab): In combination with pembrolizumab for adult patients with locally advanced or metastatic urothelial cancer, regardless of cisplatin eligibility. Monotherapy: Adult patients with locally advanced or metastatic urothelial cancer who have previously received a PD-1/PD-L1 inhibitor and platinum-containing chemotherapy.","ae":"","moa":"Enfortumab vedotin is an antibody-drug conjugate consisting of a fully human anti-Nectin-4 IgG1\u03ba monoclonal antibody conjugated to the microtubule-disrupting agent monomethyl auristatin E (MMAE) via a protease-cleavable maleimidocaproyl valine-citrulline linker. Nectin-4 is a cell adhesion molecule expressed in urothelial cancers. Upon binding to Nectin-4, the ADC undergoes internalization, linker","pk":"Tmax: end of infusion. ADC Half-life: ~3.4 days. MMAE Half-life: ~2.6 days. Vd (ADC): 11.4 L. Protein binding (MMAE): 68\u201382%. MMAE metabolized by CYP3A4. Elimination: MMAE primarily in feces. Steady state by Cycle 1.","t":[{"name":"EV-301","desc":"Enfortumab vedotin vs. chemotherapy in previously treated advanced urothelial cancer. Phase III, n=608."}]},{"s":"pemazyre","b":"Pemazyre","g":"pemigatinib","c":"FGFR Inhibitor","a":"FDA Approved 2020","m":"Incyte","i":"Cholangiocarcinoma \u2014 previously treated, unresectable, locally advanced or metastatic, with a fibroblast growth factor receptor 2 (FGFR2) fusion or other rearrangement as detected by an FDA-approved test","d":"Cholangiocarcinoma \u2014 previously treated, unresectable, locally advanced or metastatic, with a fibroblast growth factor receptor 2 (FGFR2) fusion or other rearrangement as detected by an FDA-approved test","ae":"Hyperphosphatemia (60%), alopecia (49%), diarrhea (47%), fatigue (42%), nail toxicity (43%), nausea (40%), dysgeusia (40%), constipation (35%), stomatitis (34%), dry eye (34%), dry mouth (34%), decreased appetite (33%), vomiting (27%), arthralgia (25%), abdominal pain (23%), dry skin (22%), back pain (20%)","moa":"Pemigatinib is a selective, potent, oral inhibitor of FGFR1, FGFR2, and FGFR3 with lower activity against FGFR4. In cholangiocarcinoma, FGFR2 fusions or rearrangements generate constitutively active FGFR2 fusion proteins that drive tumor proliferation. Pemigatinib inhibits these aberrant FGFR2 fusion proteins, blocking downstream RAS-MAPK and PI3K-AKT signaling and inducing tumor cell death.","pk":"Tmax: 1-2 hours. Half-life: approximately 15.4 hours. Protein binding: 97.4%. Metabolized primarily by CYP3A4. Fecal excretion (82%), urinary excretion (12%).","t":[{"name":"FIGHT-202","desc":"Pemigatinib in FGFR2 fusion/rearrangement-positive cholangiocarcinoma. Phase II, n=146."}]},{"s":"pluvicto","b":"Pluvicto","g":"","c":"Radioligand Therapy (PSMA-targeted)","a":"FDA Approved 2022","m":"Novartis","i":"PSMA-positive metastatic castration-resistant prostate cancer (mCRPC) in adult patients who have been treated with androgen receptor pathway inhibition and taxane-based chemotherapy.","d":"PSMA-positive metastatic castration-resistant prostate cancer (mCRPC) in adult patients who have been treated with androgen receptor pathway inhibition and taxane-based chemotherapy.","ae":"","moa":"","pk":"","t":[{"name":"VISION","desc":"177Lu-PSMA-617 + BSC vs. BSC in PSMA-positive mCRPC. Phase III, n=831."}]},{"s":"polivy","b":"Polivy","g":"polatuzumab vedotin-piiq","c":"Antibody-Drug Conjugate (CD79b-targeted)","a":"FDA Approved 2019","m":"Genentech","i":"Diffuse large B-cell lymphoma (DLBCL) \u2014 previously untreated, in combination with rituximab, cyclophosphamide, doxorubicin, and prednisone (pola-R-CHP); Relapsed or refractory DLBCL \u2014 after at least two prior therapies, in combination with bendamustine and rituximab","d":"Diffuse large B-cell lymphoma (DLBCL) \u2014 previously untreated, in combination with rituximab, cyclophosphamide, doxorubicin, and prednisone (pola-R-CHP); Relapsed or refractory DLBCL \u2014 after at least two prior therapies, in combination with bendamustine and rituximab","ae":"Peripheral neuropathy (40%), nausea (29%), fatigue (27%), diarrhea (26%), neutropenia (28%), constipation (20%), decreased appetite (18%), vomiting (17%), pyrexia (17%), anemia (14%), thrombocytopenia (13%)","moa":"Polatuzumab vedotin is an antibody-drug conjugate comprising a humanized anti-CD79b IgG1 antibody conjugated to MMAE (monomethyl auristatin E) via a cleavable MC-vc-PAB linker. CD79b is a B-cell\u2013specific component of the B-cell receptor signaling complex expressed on most B-cell malignancies. Upon binding CD79b, the ADC is internalized and MMAE is released, which disrupts the microtubule network, ","pk":"Half-life: approximately 12 days (ADC). Steady-state by Cycle 3. MMAE is primarily metabolized by CYP3A4. Primarily excreted in feces.","t":[{"name":"POLARIX","desc":"Pola-R-CHP vs. R-CHOP in 1L DLBCL. Phase III, n=879."}]},{"s":"pomalyst","b":"Pomalyst","g":"pomalidomide","c":"Immunomodulatory Agent (IMiD)","a":"FDA Approved 2013","m":"Bristol-Myers Squibb (Celgene)","i":"Multiple myeloma \u2014 in combination with dexamethasone in patients who have received at least two prior therapies including lenalidomide and a proteasome inhibitor and have demonstrated disease progression on or within 60 days of completion of the last therapy; AIDS-related Kaposi sarcoma \u2014 after failure of highly active antiretroviral therapy (HAART) or in those for whom HAART is not an option","d":"Multiple myeloma \u2014 in combination with dexamethasone in patients who have received at least two prior therapies including lenalidomide and a proteasome inhibitor and have demonstrated disease progression on or within 60 days of completion of the last therapy; AIDS-related Kaposi sarcoma \u2014 after failure of highly active antiretroviral therapy (HAART) or in those for whom HAART is not an option","ae":"Fatigue (55%), neutropenia (52%), anemia (38%), constipation (36%), nausea (36%), diarrhea (34%), dyspnea (34%), upper respiratory tract infection (32%), back pain (25%), pyrexia (19%), bone pain (16%)","moa":"Pomalidomide is an immunomodulatory agent with direct anti-myeloma tumoricidal activity, immune modulation, and stromal cell interaction inhibition. It binds to cereblon (CRBN), leading to enhanced ubiquitination and proteasomal degradation of the transcription factors Ikaros (IKZF1) and Aiolos (IKZF3). It also inhibits angiogenesis, enhances T-cell and NK-cell mediated immunity, and inhibits prod","pk":"Tmax: 2-3 hours. Half-life: approximately 7.5 hours. Protein binding: 12-44%. Metabolized by CYP1A2 and CYP3A4. Excreted in urine (73%, 2% unchanged) and feces (15%). No dose adjustment for renal impairment.","t":[{"name":"MM-003","desc":"Pomalidomide + low-dose dex vs. high-dose dex in relapsed/refractory MM. Phase III, n=455."}]},{"s":"poteligeo","b":"Poteligeo","g":"","c":"Anti-CCR4 Monoclonal Antibody","a":"FDA Approved 2018","m":"Kyowa Kirin","i":"Relapsed or refractory mycosis fungoides (MF) or S\u00e9zary syndrome (SS) in adults who have received at least one prior systemic therapy.","d":"Relapsed or refractory mycosis fungoides (MF) or S\u00e9zary syndrome (SS) in adults who have received at least one prior systemic therapy.","ae":"","moa":"","pk":"","t":[{"name":"MAVORIC","desc":"Mogamulizumab vs. vorinostat in relapsed/refractory CTCL. Phase III, n=372."}]},{"s":"provenge","b":"Provenge","g":"","c":"Autologous Cellular Immunotherapy","a":"FDA Approved 2010","m":"Dendreon","i":"Asymptomatic or minimally symptomatic metastatic castration-resistant prostate cancer (mCRPC).","d":"Asymptomatic or minimally symptomatic metastatic castration-resistant prostate cancer (mCRPC).","ae":"","moa":"","pk":"","t":[{"name":"IMPACT","desc":"Sipuleucel-T vs. placebo in metastatic castration-resistant prostate cancer. Phase III, n=512."}]},{"s":"retevmo","b":"Retevmo","g":"selpercatinib","c":"RET Kinase Inhibitor","a":"FDA Approved 2020","m":"Eli Lilly","i":"Non-small cell lung cancer \u2014 RET gene fusion-positive, locally advanced or metastatic; Medullary thyroid cancer \u2014 RET-mutant, advanced or metastatic requiring systemic therapy (age \u226512 years); Thyroid cancer \u2014 RET gene fusion-positive, advanced or metastatic requiring systemic therapy, refractory to radioactive iodine (if applicable); Solid tumors \u2014 RET gene fusion-positive, locally advanced or metastatic, progressed on or after prior systemic treatment or with no satisfactory alternative","d":"Non-small cell lung cancer \u2014 RET gene fusion-positive, locally advanced or metastatic; Medullary thyroid cancer \u2014 RET-mutant, advanced or metastatic requiring systemic therapy (age \u226512 years); Thyroid cancer \u2014 RET gene fusion-positive, advanced or metastatic requiring systemic therapy, refractory to radioactive iodine (if applicable); Solid tumors \u2014 RET gene fusion-positive, locally advanced or me","ae":"Edema (46%), diarrhea (43%), fatigue (42%), dry mouth (39%), hypertension (35%), abdominal pain (30%), constipation (29%), rash (27%), nausea (25%), headache (23%), AST increased (51%), ALT increased (45%)","moa":"Selpercatinib is a kinase inhibitor targeting wild-type RET (rearranged during transfection), oncogenic RET mutants (including the gatekeeper V804L/M mutations), and RET fusion proteins. It inhibits RET at sub-nanomolar concentrations, blocking RET-mediated cell proliferation. Selpercatinib has minimal activity against VEGFR2 at therapeutic concentrations, differentiating it from multi-kinase inhi","pk":"Tmax: 2 hours. Half-life: approximately 32 hours. Protein binding: 97%. Metabolized primarily by CYP3A4. Fecal excretion (69%), urinary excretion (24%).","t":[{"name":"LIBRETTO-001","desc":"Selpercatinib in RET fusion-positive NSCLC and RET-mutant thyroid cancers. Phase I/II, n=531."}]},{"s":"revlimid","b":"Revlimid","g":"lenalidomide","c":"","a":"FDA Approved 2005","m":"Bristol-Myers Squibb (Celgene)","i":"Multiple myeloma \u2014 in combination with dexamethasone; as maintenance therapy after autologous HSCT; Myelodysplastic syndromes (MDS) \u2014 transfusion-dependent anemia with deletion 5q with or without additional cytogenetic abnormalities; Mantle cell lymphoma (MCL) \u2014 relapsed or progressed after two prior therapies, one of which included bortezomib; Follicular lymphoma (FL) \u2014 in combination with rituximab, relapsed/refractory after at least two prior systemic therapies; Marginal zone lymphoma (MZL) \u2014","d":"Multiple myeloma \u2014 in combination with dexamethasone; as maintenance therapy after autologous HSCT; Myelodysplastic syndromes (MDS) \u2014 transfusion-dependent anemia with deletion 5q with or without additional cytogenetic abnormalities; Mantle cell lymphoma (MCL) \u2014 relapsed or progressed after two prior therapies, one of which included bortezomib; Follicular lymphoma (FL) \u2014 in combination with rituxi","ae":"Neutropenia (42%), thrombocytopenia (36%), diarrhea (30%), fatigue (28%), constipation (24%), nausea (22%), muscle cramp (18%), rash (16%), anemia (12%), pyrexia (15%)","moa":"Lenalidomide is an immunomodulatory agent with antineoplastic, anti-angiogenic, pro-erythropoietic, and immunomodulatory properties. It binds to cereblon, a substrate receptor of the CRL4-CRBN E3 ubiquitin ligase, leading to ubiquitination and proteasomal degradation of Ikaros (IKZF1) and Aiolos (IKZF3) transcription factors. This results in direct anti-tumor effects, enhanced T-cell and natural k","pk":"Tmax: 0.5-6 hours. Half-life: approximately 3 hours. Minimal protein binding (","t":[{"name":"MM-009","desc":"Lenalidomide + dexamethasone vs. placebo + dex in relapsed/refractory MM. Phase III, n=353."},{"name":"MM-010","desc":"Lenalidomide + dexamethasone vs. placebo + dex in relapsed/refractory MM (international). Phase III, n=351."}]},{"s":"revuforj","b":"Revuforj","g":"revumenib","c":"Menin Inhibitor","a":"FDA Approved 2024","m":"Syndax Pharmaceuticals","i":"Relapsed or refractory acute leukemia (acute myeloid leukemia or acute lymphoblastic leukemia or mixed-phenotype acute leukemia) with a KMT2A (MLL) translocation, as detected by an FDA-approved test, in adult and pediatric patients 1 year of age and older.","d":"Relapsed or refractory acute leukemia (acute myeloid leukemia or acute lymphoblastic leukemia or mixed-phenotype acute leukemia) with a KMT2A (MLL) translocation, as detected by an FDA-approved test, in adult and pediatric patients 1 year of age and older.","ae":"Febrile neutropenia (33%), hemorrhage (31%), nausea (30%), differentiation syndrome (16%), musculoskeletal pain (28%), QTc prolongation (25%), infection (28%), mucositis (22%), diarrhea (22%), edema (21%), rash (16%), headache (14%)","moa":"Revumenib is a selective inhibitor of the menin-KMT2A (menin-MLL) protein-protein interaction. In leukemias harboring KMT2A rearrangements, the fusion oncoprotein (MLL-fusion) requires binding to menin to drive aberrant gene expression (including HOXA9 and MEIS1) that maintains the leukemic state. By blocking the menin-MLL interaction, revumenib disrupts the oncogenic transcriptional program, rest","pk":"Tmax: 1-2 hours. Half-life: approximately 13 hours. Protein binding: ~92%. Metabolized primarily by CYP3A4. Steady-state by Day 5. Excreted in feces (63%) and urine (22%).","t":[{"name":"AUGMENT-101","desc":"Revumenib in relapsed/refractory KMT2A-rearranged acute leukemia. Phase I/II."}]},{"s":"rezlidhia","b":"Rezlidhia","g":"olutasidenib","c":"IDH1 Inhibitor","a":"FDA Approved 2022","m":"Rigel Pharmaceuticals","i":"Relapsed or refractory acute myeloid leukemia (AML) with a susceptible isocitrate dehydrogenase-1 (IDH1) mutation, as detected by an FDA-approved test.","d":"Relapsed or refractory acute myeloid leukemia (AML) with a susceptible isocitrate dehydrogenase-1 (IDH1) mutation, as detected by an FDA-approved test.","ae":"Nausea (38%), fatigue (30%), arthralgia (25%), constipation (25%), mucositis (25%), leukocytosis (23%), dyspnea (22%), rash (22%), diarrhea (21%), transaminase increase (22%), febrile neutropenia (21%), differentiation syndrome (19%)","moa":"Olutasidenib is a potent, selective, small-molecule inhibitor of mutant isocitrate dehydrogenase 1 (IDH1). Mutant IDH1 catalyzes reduction of \u03b1-ketoglutarate to the oncometabolite 2-hydroxyglutarate (2-HG), which inhibits \u03b1-KG-dependent enzymes involved in histone and DNA demethylation, resulting in epigenetic dysregulation and a block in myeloid differentiation. By inhibiting mutant IDH1, olutasi","pk":"Tmax: 2-4 hours. Half-life: approximately 55-65 hours. Protein binding: ~98%. Metabolized by CYP3A4 and esterases. Steady-state by ~2 weeks. Excreted in feces (~73%) and urine (~12%).","t":[]},{"s":"rituxan","b":"rituxan","g":"","c":"","a":"","m":"","i":"","d":"","ae":"","moa":"","pk":"","t":[]},{"s":"rituximab-rituxan-mabthera","b":"Rituximab (Rituxan/MabThera)","g":"","c":"","a":"","m":"","i":"Non-Hodgkin's lymphoma (NHL) \u2014 relapsed or refractory low-grade or follicular CD20-positive B-cell; previously untreated follicular CD20-positive B-cell (with chemotherapy); non-progressing low-grade CD20-positive B-cell after first-line CVP; previously untreated diffuse large B-cell CD20-positive (with CHOP or other anthracycline-based regimen); Chronic lymphocytic leukemia (CLL) \u2014 previously untreated and previously treated (with fludarabine and cyclophosphamide)","d":"Non-Hodgkin's lymphoma (NHL) \u2014 relapsed or refractory low-grade or follicular CD20-positive B-cell; previously untreated follicular CD20-positive B-cell (with chemotherapy); non-progressing low-grade CD20-positive B-cell after first-line CVP; previously untreated diffuse large B-cell CD20-positive (with CHOP or other anthracycline-based regimen); Chronic lymphocytic leukemia (CLL) \u2014 previously unt","ae":"Infusion reactions (77%), fever (53%), lymphopenia (48%), chills (33%), infection (31%), asthenia (26%), nausea (23%), headache (19%), angioedema (11%), pruritus (14%), rash (15%)","moa":"Rituximab is a chimeric murine/human IgG1\u03ba monoclonal antibody directed against the CD20 antigen found on the surface of pre-B and mature B lymphocytes. It binds CD20 and mediates B-cell lysis through complement-dependent cytotoxicity (CDC), antibody-dependent cell-mediated cytotoxicity (ADCC), and induction of apoptosis. CD20 is not shed from the cell surface and is not found in free form in circ","pk":"Half-life: 22 days (range 6.1-52 days). Serum levels inversely correlated with tumor burden. Detectable for 3-6 months after treatment completion.","t":[]},{"s":"rozlytrek","b":"Rozlytrek","g":"","c":"NTRK/ROS1 Inhibitor","a":"FDA Approved 2019","m":"Genentech","i":"Solid tumors with NTRK gene fusion \u2014 adult and pediatric (\u226512 years) with solid tumors that have an NTRK gene fusion without a known acquired resistance mutation, that are metastatic or where surgical resection is likely to result in severe morbidity, and who have no satisfactory alternative treatments or whose cancer has progressed following treatment; ROS1-positive metastatic NSCLC.","d":"Solid tumors with NTRK gene fusion \u2014 adult and pediatric (\u226512 years) with solid tumors that have an NTRK gene fusion without a known acquired resistance mutation, that are metastatic or where surgical resection is likely to result in severe morbidity, and who have no satisfactory alternative treatments or whose cancer has progressed following treatment; ROS1-positive metastatic NSCLC.","ae":"","moa":"","pk":"","t":[]},{"s":"rubraca","b":"Rubraca","g":"rucaparib","c":"PARP Inhibitor","a":"FDA Approved 2016","m":"Clovis Oncology","i":"Ovarian cancer \u2014 maintenance treatment of recurrent epithelial ovarian, fallopian tube, or primary peritoneal cancer who are in complete or partial response to platinum-based chemotherapy","d":"Ovarian cancer \u2014 maintenance treatment of recurrent epithelial ovarian, fallopian tube, or primary peritoneal cancer who are in complete or partial response to platinum-based chemotherapy","ae":"Nausea (77%), fatigue (73%), abdominal pain (46%), rash (43%), dysgeusia (39%), anemia (44%), constipation (37%), vomiting (37%), diarrhea (34%), thrombocytopenia (21%), dyspnea (21%), decreased appetite (23%)","moa":"Rucaparib is an inhibitor of poly(ADP-ribose) polymerase (PARP) enzymes, including PARP-1, PARP-2, and PARP-3. PARP inhibition by rucaparib induces cytotoxicity via trapping of PARP-DNA complexes at sites of DNA damage, preventing DNA repair, causing DNA double-strand breaks, and exploiting synthetic lethality in tumor cells with deficient homologous recombination repair (HRR), including BRCA1/2 m","pk":"Tmax: 1.9 hours. Half-life: approximately 17-19 hours. Protein binding: 70%. Metabolized by CYP2D6 and to lesser extent CYP1A2 and CYP3A4. Primarily excreted in urine (64%) and feces (28%).","t":[{"name":"ARIEL3","desc":"Rucaparib maintenance vs. placebo in platinum-sensitive recurrent ovarian cancer. Phase III, n=564."}]},{"s":"rydapt","b":"Rydapt","g":"midostaurin","c":"Multi-Kinase Inhibitor (FLT3/KIT)","a":"FDA Approved 2017","m":"Novartis","i":"Acute myeloid leukemia (AML) \u2014 newly diagnosed, FLT3 mutation-positive, in combination with standard cytarabine and daunorubicin induction and cytarabine consolidation; Aggressive systemic mastocytosis (ASM), systemic mastocytosis with associated hematological neoplasm (SM-AHN), or mast cell leukemia (MCL)","d":"Acute myeloid leukemia (AML) \u2014 newly diagnosed, FLT3 mutation-positive, in combination with standard cytarabine and daunorubicin induction and cytarabine consolidation; Aggressive systemic mastocytosis (ASM), systemic mastocytosis with associated hematological neoplasm (SM-AHN), or mast cell leukemia (MCL)","ae":"","moa":"Midostaurin is a multi-kinase inhibitor that inhibits multiple receptor tyrosine kinases including wild-type and mutated FLT3 (ITD and TKD mutations), KIT (wild-type and D816V mutant), PDGFR-\u03b1/\u03b2, VEGFR2, and members of the serine/threonine kinase protein kinase C (PKC) family. In AML, it inhibits FLT3 receptor signaling. In systemic mastocytosis, it inhibits KIT D816V-driven mast cell proliferatio","pk":"Tmax: 1-3 hours. Half-life: 21 hours (active metabolites: 32-482 hours). Protein binding: 94% (midostaurin and metabolites). Metabolized by CYP3A4. Fecal excretion (78%), urinary excretion (4%).","t":[{"name":"RATIFY","desc":"Midostaurin + chemo vs. placebo + chemo in FLT3-mutated AML. Phase III, n=717."}]},{"s":"rylaze","b":"Rylaze","g":"asparaginase erwinia chrysanthemi (recombinant)","c":"Enzyme Therapy (L-Asparaginase)","a":"FDA Approved 2021","m":"Jazz Pharmaceuticals","i":"Acute lymphoblastic leukemia (ALL) and lymphoblastic lymphoma (LBL) \u2014 as a component of a multi-agent chemotherapeutic regimen in adult and pediatric patients 1 month of age and older who have developed hypersensitivity to E. coli-derived asparaginase.","d":"Acute lymphoblastic leukemia (ALL) and lymphoblastic lymphoma (LBL) \u2014 as a component of a multi-agent chemotherapeutic regimen in adult and pediatric patients 1 month of age and older who have developed hypersensitivity to E. coli-derived asparaginase.","ae":"Abnormal liver tests (27%), nausea (16%), musculoskeletal pain (12%), infection (11%), fatigue (10%), febrile neutropenia (9%), headache (8%), pancreatitis (6%), pyrexia (5%), hypersensitivity (4%), thrombosis (4%)","moa":"Rylaze contains recombinant L-asparaginase derived from Erwinia chrysanthemi (now classified as Dickeya chrysanthemi). L-asparaginase catalyzes the hydrolysis of the amino acid L-asparagine to aspartic acid and ammonia. Leukemic lymphoblasts lack asparagine synthetase and are dependent on exogenous L-asparagine for protein synthesis and survival. Depletion of circulating L-asparagine by the enzyme","pk":"Target serum asparaginase activity (SAA) level: \u22650.1 IU/mL (nadir 48-hour). Tmax: ~12-16 hours after IM injection. Half-life: approximately 16-18 hours. Serum asparagine depletion maintained with MWF dosing schedule.","t":[{"name":"JZP458-201","desc":"Recombinant erwinia asparaginase as substitute in ALL/LBL with hypersensitivity. Phase II/III."}]},{"s":"sarclisa","b":"Sarclisa","g":"isatuximab-irfc","c":"Anti-CD38 Monoclonal Antibody","a":"","m":"Sanofi","i":"Multiple myeloma \u2014 in combination with pomalidomide and dexamethasone, for adults who have received at least two prior therapies including lenalidomide and a proteasome inhibitor; in combination with carfilzomib and dexamethasone, for relapsed or refractory after one to three prior lines of therapy","d":"Multiple myeloma \u2014 in combination with pomalidomide and dexamethasone, for adults who have received at least two prior therapies including lenalidomide and a proteasome inhibitor; in combination with carfilzomib and dexamethasone, for relapsed or refractory after one to three prior lines of therapy","ae":"Infusion-related reactions (38%), neutropenia (46%), upper respiratory tract infection (28%), pneumonia (23%), diarrhea (26%), fatigue (20%), nausea (15%)","moa":"Isatuximab is a chimeric IgG1\u03ba monoclonal antibody that binds to a specific extracellular epitope on CD38, a transmembrane glycoprotein abundantly expressed on multiple myeloma cells. It induces tumor cell death through multiple mechanisms: complement-dependent cytotoxicity (CDC), antibody-dependent cell-mediated cytotoxicity (ADCC), antibody-dependent cellular phagocytosis (ADCP), and direct apop","pk":"Half-life: approximately 28 days. Clearance: 10.6 mL/h (decreases over time as CD38+ cells depleted). Vd: 8.0 L. Steady-state by approximately Cycle 4 (q2w). Linear PK at 10 mg/kg.","t":[]},{"s":"scemblix","b":"Scemblix","g":"","c":"STAMP Inhibitor (BCR-ABL1 Allosteric)","a":"FDA Approved 2021","m":"Novartis","i":"Ph+ CML in chronic phase, previously treated with two or more tyrosine kinase inhibitors; Ph+ CML in chronic phase with the T315I mutation.","d":"Ph+ CML in chronic phase, previously treated with two or more tyrosine kinase inhibitors; Ph+ CML in chronic phase with the T315I mutation.","ae":"","moa":"","pk":"","t":[{"name":"ASCEMBL","desc":"Asciminib vs. bosutinib in CML previously treated with \u22652 TKIs. Phase III, n=233."}]},{"s":"sprycel","b":"Sprycel","g":"","c":"BCR-ABL/SRC Kinase Inhibitor","a":"FDA Approved 2006","m":"BMS","i":"Newly diagnosed adults with Ph+ CML in chronic phase; Ph+ CML with resistance or intolerance to prior therapy including imatinib (chronic, accelerated, or myeloid/lymphoid blast phase); Ph+ ALL with resistance or intolerance to prior therapy; Pediatric patients with Ph+ CML in chronic phase.","d":"Newly diagnosed adults with Ph+ CML in chronic phase; Ph+ CML with resistance or intolerance to prior therapy including imatinib (chronic, accelerated, or myeloid/lymphoid blast phase); Ph+ ALL with resistance or intolerance to prior therapy; Pediatric patients with Ph+ CML in chronic phase.","ae":"","moa":"","pk":"","t":[{"name":"DASISION","desc":"Dasatinib vs. imatinib in newly diagnosed chronic-phase CML. Phase III, n=519."}]},{"s":"stivarga","b":"Stivarga","g":"regorafenib","c":"","a":"","m":"","i":"Metastatic colorectal cancer (CRC) previously treated with fluoropyrimidine-, oxaliplatin-, and irinotecan-based chemotherapy, anti-VEGF therapy, and anti-EGFR therapy (if KRAS wild-type); Locally advanced, unresectable, or metastatic gastrointestinal stromal tumors (GIST) previously treated with imatinib and sunitinib; Hepatocellular carcinoma (HCC) previously treated with sorafenib","d":"Metastatic colorectal cancer (CRC) previously treated with fluoropyrimidine-, oxaliplatin-, and irinotecan-based chemotherapy, anti-VEGF therapy, and anti-EGFR therapy (if KRAS wild-type); Locally advanced, unresectable, or metastatic gastrointestinal stromal tumors (GIST) previously treated with imatinib and sunitinib; Hepatocellular carcinoma (HCC) previously treated with sorafenib","ae":"Hand-foot skin reaction (53%), fatigue (47%), diarrhea (43%), hypertension (30%), decreased appetite (30%), oral mucositis (29%), dysphonia (29%), infection (21%), weight loss (14%), rash (18%)","moa":"Regorafenib is a small-molecule inhibitor of multiple membrane-bound and intracellular kinases including those involved in tumor angiogenesis (VEGFR1-3, TIE2), oncogenesis (KIT, RET, RAF1, BRAF, BRAFV600E), metastasis (VEGFR3, PDGFR, FGFR), tumor immunity (CSF1R), and the tumor microenvironment (PDGFR, FGFR).","pk":"Tmax: approximately 4 hours. Half-life: 28 hours (parent), 51 hours (M-2 metabolite), 59 hours (M-5 metabolite). Both metabolites pharmacologically active. Protein binding: 99.5%. Metabolized by CYP3A4 and UGT1A9. Excreted in feces (71%) and urine (19%).","t":[{"name":"CORRECT","desc":"Regorafenib vs. placebo in metastatic CRC after standard therapies. Phase III, n=760."},{"name":"RESORCE","desc":"Regorafenib vs. placebo in HCC after sorafenib. Phase III, n=573."}]},{"s":"sutent","b":"Sutent","g":"sunitinib","c":"Multi-Kinase Inhibitor","a":"FDA Approved 2006","m":"Pfizer","i":"Gastrointestinal stromal tumor (GIST) after disease progression on or intolerance to imatinib; Advanced renal cell carcinoma (RCC); Progressive, well-differentiated pancreatic neuroendocrine tumors (pNET) in patients with unresectable, locally advanced, or metastatic disease","d":"Gastrointestinal stromal tumor (GIST) after disease progression on or intolerance to imatinib; Advanced renal cell carcinoma (RCC); Progressive, well-differentiated pancreatic neuroendocrine tumors (pNET) in patients with unresectable, locally advanced, or metastatic disease","ae":"Fatigue (62%), diarrhea (61%), nausea (52%), mucositis/stomatitis (47%), vomiting (39%), dyspepsia (34%), decreased appetite (33%), abdominal pain (30%), hypertension (34%), skin discoloration (30%), rash (24%), hand-foot syndrome (29%)","moa":"Sunitinib is a multi-kinase inhibitor that targets PDGFR\u03b1 and PDGFR\u03b2, VEGFR1-3, KIT, FLT3, CSF-1R, and RET. It inhibits tumor cell proliferation and angiogenesis by blocking receptor tyrosine kinase signaling. The anti-tumor activity results from inhibition of multiple receptor tyrosine kinases involved in tumor growth, pathologic angiogenesis, and metastatic progression.","pk":"Tmax: 6-12 hours. Half-life: 40-60 hours (active metabolite: 80-110 hours). Protein binding: 95% (sunitinib), 90% (metabolite). Metabolized primarily by CYP3A4. Primarily excreted in feces (61%).","t":[]},{"s":"tafinlar","b":"Tafinlar","g":"","c":"BRAF Inhibitor","a":"FDA Approved 2013","m":"Novartis","i":"Unresectable or metastatic melanoma with BRAF V600E mutation (with trametinib); Adjuvant treatment of melanoma with BRAF V600E/K mutations following complete resection (with trametinib); Metastatic NSCLC with BRAF V600E mutation (with trametinib); Locally advanced or metastatic anaplastic thyroid cancer with BRAF V600E mutation (with trametinib); Solid tumors with BRAF V600E mutation following prior treatment with no satisfactory alternatives (with trametinib, adults); Low-grade glioma with BRAF","d":"Unresectable or metastatic melanoma with BRAF V600E mutation (with trametinib); Adjuvant treatment of melanoma with BRAF V600E/K mutations following complete resection (with trametinib); Metastatic NSCLC with BRAF V600E mutation (with trametinib); Locally advanced or metastatic anaplastic thyroid cancer with BRAF V600E mutation (with trametinib); Solid tumors with BRAF V600E mutation following pri","ae":"","moa":"","pk":"","t":[]},{"s":"tagrisso","b":"Tagrisso","g":"osimertinib","c":"EGFR TKI (3rd Generation)","a":"FDA Approved 2015","m":"AstraZeneca","i":"First-line monotherapy: Adult patients with metastatic NSCLC whose tumors have EGFR exon 19 deletions or exon 21 L858R mutations, as detected by an FDA-approved test. First-line combination: With platinum-based chemotherapy for locally advanced or metastatic NSCLC with EGFR exon 19 deletions or exon 21 L858R mutations. Stage III unresectable: Adult patients with locally advanced, unresectable (stage III) NSCLC whose disease has not progressed during or following concurrent or sequential platinum","d":"First-line monotherapy: Adult patients with metastatic NSCLC whose tumors have EGFR exon 19 deletions or exon 21 L858R mutations, as detected by an FDA-approved test. First-line combination: With platinum-based chemotherapy for locally advanced or metastatic NSCLC with EGFR exon 19 deletions or exon 21 L858R mutations. Stage III unresectable: Adult patients with locally advanced, unresectable (sta","ae":"","moa":"Osimertinib is a third-generation, irreversible EGFR tyrosine kinase inhibitor that binds to certain mutant forms of EGFR (T790M, L858R, exon 19 deletion) at approximately 9-fold lower concentrations than wild-type EGFR. It also inhibits HER2, HER3, HER4, ACK1, and BLK at clinically relevant concentrations. Osimertinib distributes to the brain, with brain-to-plasma AUC ratios of approximately 2 in","pk":"Tmax: 6 hours (range 3\u201324). Bioavailability not determined for tablets. Vd: 918 L. Protein binding: 95%. Metabolized by CYP3A4/5 to active metabolites AZ5104 and AZ7550 (each ~10% of parent exposure). Half-life: ~48 hours. Elimination: feces 68%, urine 14%. Steady state by Day 15.","t":[{"name":"FLAURA","desc":"Osimertinib vs. erlotinib/gefitinib as first-line treatment in EGFR-mutant advanced NSCLC. Phase III, n=556."},{"name":"FLAURA2","desc":"Osimertinib + chemotherapy vs. osimertinib monotherapy in first-line EGFR-mutant advanced NSCLC. Phase III, n=557."},{"name":"ADAURA","desc":"Adjuvant osimertinib vs. placebo in resected stage IB-IIIA EGFR-mutant NSCLC. Phase III, n=682."},{"name":"LAURA","desc":"Osimertinib vs. placebo after chemoradiation in unresectable stage III EGFR-mutant NSCLC. Phase III, n=216."},{"name":"AURA3","desc":"Osimertinib vs. platinum-pemetrexed in T790M+ advanced NSCLC after prior EGFR TKI. Phase III, n=419."}]},{"s":"talvey","b":"Talvey","g":"talquetamab-tgvs","c":"Bispecific Antibody (GPRC5D \u00d7 CD3)","a":"FDA Approved 2023","m":"Janssen","i":"Multiple myeloma \u2014 relapsed or refractory, after at least four prior lines of therapy including a proteasome inhibitor, an immunomodulatory agent, and an anti-CD38 monoclonal antibody","d":"Multiple myeloma \u2014 relapsed or refractory, after at least four prior lines of therapy including a proteasome inhibitor, an immunomodulatory agent, and an anti-CD38 monoclonal antibody","ae":"CRS (77%), dysgeusia (63%), skin toxicity (56%), infections (57%), musculoskeletal pain (40%), nail disorders (40%), oral disorders (38%), fatigue (31%), nausea (27%), weight loss (23%), pyrexia (22%), neutropenia (57%), lymphopenia (80%), anemia (40%)","moa":"Talquetamab is a bispecific humanized IgG4 monoclonal antibody that binds to GPRC5D (G Protein-Coupled Receptor Class C Group 5 Member D) on myeloma cells and CD3 on T cells. GPRC5D is a novel target broadly expressed on myeloma cells with limited normal tissue expression (keratinocytes, hair follicles, oral mucosa). By bridging T cells to GPRC5D-expressing myeloma cells, talquetamab redirects T-c","pk":"Half-life: approximately 10 days at target dose. Step-up dosing minimizes CRS severity. Non-linear PK at lower doses due to target-mediated drug disposition. Steady-state by approximately Cycle 5.","t":[]},{"s":"talzenna","b":"Talzenna","g":"","c":"PARP Inhibitor","a":"FDA Approved 2018","m":"Pfizer","i":"Deleterious or suspected deleterious germline BRCA-mutated (gBRCAm) HER2-negative locally advanced or metastatic breast cancer, as detected by an FDA-approved test; Metastatic castration-resistant prostate cancer (mCRPC) with HRR gene mutations, in combination with enzalutamide.","d":"Deleterious or suspected deleterious germline BRCA-mutated (gBRCAm) HER2-negative locally advanced or metastatic breast cancer, as detected by an FDA-approved test; Metastatic castration-resistant prostate cancer (mCRPC) with HRR gene mutations, in combination with enzalutamide.","ae":"","moa":"","pk":"","t":[{"name":"EMBRACA","desc":"Talazoparib vs. physician's choice in germline BRCA-mutated HER2- metastatic breast cancer. Phase III, n=431."}]},{"s":"targretin","b":"Targretin","g":"","c":"Retinoid X Receptor (RXR) Agonist","a":"FDA Approved 1999","m":"Bausch Health","i":"Cutaneous T-cell lymphoma (CTCL) \u2014 cutaneous manifestations in patients refractory to at least one prior systemic therapy (oral); Early-stage CTCL (stage IA-IIA) refractory to or persistent despite prior therapies or intolerant of other therapies (topical gel).","d":"Cutaneous T-cell lymphoma (CTCL) \u2014 cutaneous manifestations in patients refractory to at least one prior systemic therapy (oral); Early-stage CTCL (stage IA-IIA) refractory to or persistent despite prior therapies or intolerant of other therapies (topical gel).","ae":"","moa":"","pk":"","t":[]},{"s":"tasigna","b":"Tasigna","g":"","c":"BCR-ABL Tyrosine Kinase Inhibitor","a":"FDA Approved 2007","m":"Novartis","i":"Newly diagnosed adult patients with Ph+ CML in chronic phase; Ph+ CML in chronic or accelerated phase resistant to or intolerant of prior therapy including imatinib; Pediatric Ph+ CML in chronic phase.","d":"Newly diagnosed adult patients with Ph+ CML in chronic phase; Ph+ CML in chronic or accelerated phase resistant to or intolerant of prior therapy including imatinib; Pediatric Ph+ CML in chronic phase.","ae":"","moa":"","pk":"","t":[]},{"s":"taxol","b":"Taxol","g":"paclitaxel","c":"Taxane (Microtubule-Stabilizing Agent)","a":"FDA Approved 1992","m":"Bristol-Myers Squibb (generic widely available)","i":"Ovarian cancer \u2014 first-line (with cisplatin) and subsequent therapy for metastatic carcinoma; Breast cancer \u2014 adjuvant treatment of node-positive disease following standard doxorubicin-containing combination chemotherapy, and for treatment of metastatic disease after failure of combination chemotherapy or relapse within 6 months of adjuvant chemotherapy; Non-small cell lung cancer (NSCLC) \u2014 in combination with cisplatin for first-line treatment in patients who are not candidates for surgery or r","d":"Ovarian cancer \u2014 first-line (with cisplatin) and subsequent therapy for metastatic carcinoma; Breast cancer \u2014 adjuvant treatment of node-positive disease following standard doxorubicin-containing combination chemotherapy, and for treatment of metastatic disease after failure of combination chemotherapy or relapse within 6 months of adjuvant chemotherapy; Non-small cell lung cancer (NSCLC) \u2014 in com","ae":"Neutropenia (90%, Grade 4: 52%), alopecia (87%), peripheral neuropathy (60%), myalgia/arthralgia (60%), nausea/vomiting (52%), diarrhea (38%), mucositis (31%), hypotension (12%), bradycardia (29%), injection site reactions (13%), hypersensitivity (41% any grade)","moa":"Paclitaxel promotes polymerization of tubulin dimers into microtubules and stabilizes microtubules by preventing depolymerization. This abnormal stabilization results in inhibition of the normal dynamic reorganization of the microtubule network that is essential for interphase and mitotic cellular functions. Paclitaxel induces the formation of abnormal microtubule bundles throughout the cell cycle","pk":"Biphasic elimination. Half-life: alpha 0.27 hours, beta 6.4-20 hours (dose-dependent). Non-linear PK; disproportionate increase in Cmax and AUC with increasing dose. Protein binding: 89-98%. Metabolized by CYP2C8 (major) and CYP3A4. Primarily excreted in feces (biliary) with","t":[]},{"s":"tazverik","b":"Tazverik","g":"","c":"EZH2 Inhibitor","a":"FDA Approved 2020","m":"Ipsen","i":"Epithelioid sarcoma \u2014 metastatic or locally advanced, not eligible for complete resection, in adults and pediatric patients \u226516 years; Relapsed or refractory follicular lymphoma (FL) \u2014 with EZH2 mutation (in combination with lenalidomide + rituximab) or after \u22652 prior systemic therapies; FL \u2014 in combination with lenalidomide + rituximab for relapsed/refractory FL regardless of EZH2 status.","d":"Epithelioid sarcoma \u2014 metastatic or locally advanced, not eligible for complete resection, in adults and pediatric patients \u226516 years; Relapsed or refractory follicular lymphoma (FL) \u2014 with EZH2 mutation (in combination with lenalidomide + rituximab) or after \u22652 prior systemic therapies; FL \u2014 in combination with lenalidomide + rituximab for relapsed/refractory FL regardless of EZH2 status.","ae":"","moa":"","pk":"","t":[{"name":"EZH-202","desc":"Tazemetostat in relapsed/refractory follicular lymphoma with EZH2 mutation. Phase II, n=99."}]},{"s":"tebentafusp","b":"tebentafusp","g":"","c":"","a":"","m":"","i":"","d":"","ae":"","moa":"","pk":"","t":[]},{"s":"tecartus","b":"Tecartus","g":"brexucabtagene autoleucel","c":"CAR T-Cell Therapy (CD19-targeted)","a":"FDA Approved 2020","m":"Kite/Gilead Sciences","i":"Mantle cell lymphoma (MCL) \u2014 relapsed or refractory; B-cell precursor acute lymphoblastic leukemia (ALL) \u2014 relapsed or refractory, in adults.","d":"Mantle cell lymphoma (MCL) \u2014 relapsed or refractory; B-cell precursor acute lymphoblastic leukemia (ALL) \u2014 relapsed or refractory, in adults.","ae":"CRS (89-91%), pyrexia (94%), hypotension (56%), fatigue (47%), encephalopathy (41-50%), tachycardia (38-42%), nausea (37%), headache (33-37%), chills (27-33%), febrile neutropenia (25-30%), diarrhea (24-26%), infections (31%), tremor (24-30%)","moa":"Brexucabtagene autoleucel is a CD19-directed genetically modified autologous T-cell immunotherapy. Patient T cells are collected and genetically modified using a retroviral vector to express a chimeric antigen receptor (CAR) comprising an anti-CD19 scFv, CD28 costimulatory domain, and CD3-zeta signaling domain. The manufacturing process includes T-cell enrichment to remove circulating tumor cells ","pk":"Peak CAR T-cell expansion: median 7-14 days. CAR T cells detectable in blood for months. T-cell enrichment manufacturing step removes circulating tumor cells, differentiating from Yescarta. Higher peak expansion correlated with CRS severity and response.","t":[{"name":"ZUMA-2","desc":"Brexucabtagene autoleucel in relapsed/refractory mantle cell lymphoma. Phase II, n=74."}]},{"s":"tecentriq","b":"Tecentriq","g":"atezolizumab","c":"","a":"","m":"","i":"Non-small cell lung cancer (multiple settings); Small cell lung cancer (extensive-stage, first-line with carboplatin and etoposide); Hepatocellular carcinoma (with bevacizumab); Melanoma (with cobimetinib and vemurafenib); Alveolar soft part sarcoma","d":"Non-small cell lung cancer (multiple settings); Small cell lung cancer (extensive-stage, first-line with carboplatin and etoposide); Hepatocellular carcinoma (with bevacizumab); Melanoma (with cobimetinib and vemurafenib); Alveolar soft part sarcoma","ae":"","moa":"Atezolizumab is a humanized IgG1 monoclonal antibody that binds to PD-L1 and blocks its interactions with both PD-1 and B7.1 receptors. This releases PD-L1/PD-1-mediated inhibition of the anti-tumor immune response, including reactivation of the anti-tumor immune response without inducing antibody-dependent cellular cytotoxicity.","pk":"Half-life: 27 days. Clearance: 0.20 L/day. Vd: 6.9 L. Steady-state by 6-9 weeks. Linear PK at doses 1-20 mg/kg. Not affected by age, body weight, gender, albumin, tumor burden, or mild-moderate renal/hepatic impairment.","t":[]},{"s":"tecvayli","b":"Tecvayli","g":"teclistamab-cqyv","c":"Bispecific Antibody (BCMA \u00d7 CD3)","a":"","m":"Janssen","i":"Multiple myeloma \u2014 relapsed or refractory, after at least four prior lines of therapy including a proteasome inhibitor, an immunomodulatory agent, and an anti-CD38 monoclonal antibody","d":"Multiple myeloma \u2014 relapsed or refractory, after at least four prior lines of therapy including a proteasome inhibitor, an immunomodulatory agent, and an anti-CD38 monoclonal antibody","ae":"Infections (76%), CRS (72%), fatigue (46%), musculoskeletal pain (36%), injection site reactions (33%), nausea (24%), pyrexia (23%), headache (21%), hemorrhage (20%), diarrhea (17%), neutropenia (71%), anemia (52%), lymphopenia (92%)","moa":"Teclistamab is a bispecific humanized IgG4 monoclonal antibody that binds to B-cell maturation antigen (BCMA) on myeloma cells and CD3 on T cells. By simultaneously binding both targets, it redirects T cells to BCMA-expressing myeloma cells, inducing T-cell activation, cytokine release, and T-cell mediated killing of myeloma cells.","pk":"Half-life: approximately 5.5 days at target dose. Steady-state by Cycle 3. Non-linear PK during step-up. Step-up dosing reduces CRS incidence. Clearance: 0.6 L/day.","t":[]},{"s":"temodal","b":"temodal","g":"","c":"","a":"","m":"","i":"","d":"","ae":"","moa":"","pk":"","t":[]},{"s":"temodar","b":"Temodar","g":"temozolomide","c":"","a":"FDA Approved 1999","m":"Merck","i":"Glioblastoma multiforme \u2014 newly diagnosed, concomitantly with radiotherapy and then as maintenance; Refractory anaplastic astrocytoma \u2014 patients who have experienced disease progression on a drug regimen containing nitrosourea and procarbazine","d":"Glioblastoma multiforme \u2014 newly diagnosed, concomitantly with radiotherapy and then as maintenance; Refractory anaplastic astrocytoma \u2014 patients who have experienced disease progression on a drug regimen containing nitrosourea and procarbazine","ae":"","moa":"Temozolomide is a prodrug that undergoes rapid nonenzymatic conversion at physiologic pH to the reactive compound MTIC (5-(3-methyltriazen-1-yl)-imidazole-4-carboxamide). MTIC methylates DNA at the O\u2076 and N\u2077 positions of guanine. This methylation triggers the mismatch repair system, leading to DNA strand breaks and apoptosis. The cytotoxicity is enhanced in cells with deficient O\u2076-methylguanine-DN","pk":"Tmax: 1 hour (oral). Bioavailability: approximately 100%. Half-life: 1.8 hours. Protein binding: 15%. Crosses blood-brain barrier (CNS concentrations approximately 30% of plasma). Excreted primarily in urine (38% as unchanged MTIC, 6% as unchanged temozolomide).","t":[]},{"s":"tibsovo","b":"Tibsovo","g":"ivosidenib","c":"IDH1 Inhibitor","a":"FDA Approved 2018","m":"Servier","i":"Acute myeloid leukemia (AML) \u2014 with a susceptible IDH1 mutation: newly diagnosed in patients \u226575 years or with comorbidities precluding induction chemo (monotherapy or with azacitidine); relapsed or refractory AML; Cholangiocarcinoma \u2014 locally advanced or metastatic, previously treated, with an IDH1 mutation as detected by an FDA-approved test","d":"Acute myeloid leukemia (AML) \u2014 with a susceptible IDH1 mutation: newly diagnosed in patients \u226575 years or with comorbidities precluding induction chemo (monotherapy or with azacitidine); relapsed or refractory AML; Cholangiocarcinoma \u2014 locally advanced or metastatic, previously treated, with an IDH1 mutation as detected by an FDA-approved test","ae":"Fatigue (37%), leukocytosis (30%), arthralgia (25%), diarrhea (24%), dyspnea (23%), edema (22%), nausea (21%), mucositis (18%), ECG QT prolonged (10%), rash (14%), decreased appetite (14%)","moa":"Ivosidenib is a small-molecule inhibitor of the mutant isocitrate dehydrogenase 1 (IDH1) enzyme. Susceptible IDH1 mutations (R132H, R132C, R132L, R132G, R132S) produce the oncometabolite 2-hydroxyglutarate (2-HG), which causes epigenetic alterations and blocks cellular differentiation. Ivosidenib inhibits the mutant IDH1 enzyme, reducing 2-HG levels and restoring cellular differentiation.","pk":"Tmax: 3 hours. Half-life: approximately 93 hours at steady state. Protein binding: 92-96%. Metabolized primarily by CYP3A4 (also induces its own metabolism). Fecal excretion (77%), urinary excretion (17%).","t":[]},{"s":"tivdak","b":"Tivdak","g":"tisotumab vedotin-tftv","c":"Antibody-Drug Conjugate (Tissue Factor-targeted)","a":"FDA Approved 2021","m":"Seagen (Pfizer)/Genmab","i":"Cervical cancer \u2014 recurrent or metastatic, with disease progression on or after chemotherapy","d":"Cervical cancer \u2014 recurrent or metastatic, with disease progression on or after chemotherapy","ae":"Epistaxis (42%), nausea (30%), fatigue (28%), conjunctivitis (27%), hemorrhage (62%), alopecia (26%), peripheral neuropathy (42%), diarrhea (20%), decreased appetite (16%), vomiting (14%), dry eye (16%)","moa":"Tisotumab vedotin is an antibody-drug conjugate comprising a human anti-tissue factor (TF) IgG1 monoclonal antibody conjugated to MMAE via a protease-cleavable MC-vc-PAB linker. Tissue factor is a transmembrane protein overexpressed on many solid tumors, including cervical cancer. Upon TF binding and internalization, MMAE is released intracellularly, disrupting the microtubule network and inducing","pk":"Tmax: end of infusion. ADC half-life: approximately 3.1 days. Payload (MMAE) half-life: 2-4 days. Clearance: 1.63 L/day. Vd: 9.3 L. MMAE metabolized by CYP3A4. Steady-state by Cycle 3.","t":[]},{"s":"trodelvy","b":"Trodelvy","g":"sacituzumab govitecan-hziy","c":"Antibody-Drug Conjugate (Trop-2-targeted)","a":"FDA Approved 2020","m":"Gilead Sciences","i":"Unresectable locally advanced or metastatic triple-negative breast cancer (TNBC) after \u22652 prior systemic therapies (including \u22651 for metastatic disease); Unresectable locally advanced or metastatic HR-positive/HER2-negative breast cancer after endocrine-based therapy and \u22652 additional systemic therapies; Locally advanced or metastatic urothelial cancer after prior platinum-based chemo and checkpoint inhibitor","d":"Unresectable locally advanced or metastatic triple-negative breast cancer (TNBC) after \u22652 prior systemic therapies (including \u22651 for metastatic disease); Unresectable locally advanced or metastatic HR-positive/HER2-negative breast cancer after endocrine-based therapy and \u22652 additional systemic therapies; Locally advanced or metastatic urothelial cancer after prior platinum-based chemo and checkpoi","ae":"","moa":"Sacituzumab govitecan is an antibody-drug conjugate composed of a humanized anti-Trop-2 IgG1\u03ba antibody conjugated to SN-38 (active metabolite of irinotecan) via a hydrolyzable CL2A linker. It targets Trop-2-expressing cancer cells, undergoes internalization, and releases SN-38 (a topoisomerase I inhibitor) to cause DNA damage and cell death.","pk":"Tmax: end of infusion. ADC half-life: ~16 hours. SN-38 (payload) half-life: ~18 hours. Clearance: 1.64 L/h. Vd: 15.1 L. SN-38 metabolized by UGT1A1 (Gilbert syndrome patients at higher risk for neutropenia). Excreted in urine (13%) and feces (55%).","t":[{"name":"ASCENT","desc":"Sacituzumab govitecan vs. physician's choice in metastatic TNBC. Phase III, n=468."}]},{"s":"tukysa","b":"Tukysa","g":"tucatinib","c":"HER2 TKI (Selective)","a":"FDA Approved 2020","m":"Seagen/AstraZeneca","i":"HER2+ Metastatic Breast Cancer: In combination with trastuzumab and capecitabine for adult patients with HER2-positive unresectable locally advanced or metastatic breast cancer, including patients with brain metastases, who have received one or more prior anti-HER2-based regimens in the metastatic setting. HER2+ Metastatic Colorectal Cancer: In combination with trastuzumab for adult patients with RAS wild-type, HER2-positive unresectable or metastatic colorectal cancer that has progressed after ","d":"HER2+ Metastatic Breast Cancer: In combination with trastuzumab and capecitabine for adult patients with HER2-positive unresectable locally advanced or metastatic breast cancer, including patients with brain metastases, who have received one or more prior anti-HER2-based regimens in the metastatic setting. HER2+ Metastatic Colorectal Cancer: In combination with trastuzumab for adult patients with ","ae":"","moa":"Tucatinib is a tyrosine kinase inhibitor that is highly selective for the kinase domain of HER2 with minimal inhibition of EGFR. In combination with trastuzumab, tucatinib demonstrated enhanced anti-tumor activity compared with either agent alone. Tucatinib has demonstrated activity in the CNS, supporting its use in patients with brain metastases.","pk":"Tmax: 2 hours. Bioavailability not characterized. Vd: 1670 L. Protein binding: 97%. Metabolized by CYP2C8 and CYP3A. Half-life: 8.5 hours. Steady state within 4 days. Elimination: feces 86%, urine 5%.","t":[{"name":"HER2CLIMB","desc":"Tucatinib + trastuzumab + capecitabine vs. placebo + trastuzumab + capecitabine in HER2+ metastatic breast cancer. Phase III, n=612."},{"name":"MOUNTAINEER","desc":"Tucatinib + trastuzumab in HER2+, RAS wild-type metastatic CRC. Phase II, n=84."}]},{"s":"velcade","b":"Velcade","g":"bortezomib","c":"","a":"","m":"Takeda","i":"Multiple myeloma \u2014 in combination with other agents for newly diagnosed and relapsed/refractory disease; Mantle cell lymphoma \u2014 in patients who have received at least one prior therapy","d":"Multiple myeloma \u2014 in combination with other agents for newly diagnosed and relapsed/refractory disease; Mantle cell lymphoma \u2014 in patients who have received at least one prior therapy","ae":"Nausea (55%), diarrhea (52%), thrombocytopenia (43%), fatigue (41%), peripheral neuropathy (37%), constipation (34%), vomiting (33%), neutropenia (24%), anorexia (21%), pyrexia (21%)","moa":"Bortezomib is a reversible inhibitor of the chymotrypsin-like activity of the 26S proteasome, a large protein complex that degrades ubiquitinated proteins. Proteasome inhibition disrupts multiple cell signaling cascades, including NF-\u03baB pathway, resulting in cell cycle arrest and apoptosis in malignant cells. Bortezomib also inhibits angiogenesis and modulates the bone marrow microenvironment.","pk":"Mean elimination half-life: 40-193 hours after multiple dosing. Vd: 498-1884 L/m\u00b2. Metabolized primarily by CYP3A4, CYP2C19, and CYP1A2. Protein binding: 83%. SC bioavailability: 100% relative to IV.","t":[{"name":"APEX","desc":"Bortezomib vs. dexamethasone in relapsed multiple myeloma. Phase III, n=669."},{"name":"VISTA","desc":"Bortezomib + melphalan/prednisone vs. MP in newly diagnosed MM not eligible for transplant. Phase III, n=682."}]},{"s":"venclexta","b":"Venclexta","g":"venetoclax","c":"BCL-2 Inhibitor","a":"FDA Approved 2016","m":"AbbVie/Genentech","i":"Chronic lymphocytic leukemia (CLL)/Small lymphocytic lymphoma (SLL) \u2014 as monotherapy or in combination with obinutuzumab or rituximab; Acute myeloid leukemia (AML) \u2014 newly diagnosed, in combination with azacitidine, decitabine, or low-dose cytarabine in adults \u226575 years or with comorbidities precluding intensive induction chemotherapy","d":"Chronic lymphocytic leukemia (CLL)/Small lymphocytic lymphoma (SLL) \u2014 as monotherapy or in combination with obinutuzumab or rituximab; Acute myeloid leukemia (AML) \u2014 newly diagnosed, in combination with azacitidine, decitabine, or low-dose cytarabine in adults \u226575 years or with comorbidities precluding intensive induction chemotherapy","ae":"","moa":"Venetoclax is a selective inhibitor of B-cell lymphoma 2 (BCL-2), an anti-apoptotic protein. Overexpression of BCL-2 has been demonstrated in CLL cells and AML blasts, where it mediates tumor cell survival and has been associated with resistance to chemotherapy. Venetoclax binds directly to the BH3-binding groove of BCL-2, displacing pro-apoptotic proteins (BIM), restoring apoptosis. This mechanis","pk":"Tmax: 5-8 hours. Half-life: approximately 26 hours. Protein binding: >99.9%. Metabolized primarily by CYP3A4. Fecal excretion (>99.9%).","t":[{"name":"CLL14","desc":"Venetoclax + obinutuzumab vs. chlorambucil + obinutuzumab in 1L CLL. Phase III, n=432."},{"name":"MURANO","desc":"Venetoclax + rituximab vs. bendamustine + rituximab in relapsed/refractory CLL. Phase III, n=389."}]},{"s":"venetoclax","b":"venetoclax","g":"","c":"","a":"","m":"","i":"","d":"","ae":"","moa":"","pk":"","t":[]},{"s":"verzenio","b":"Verzenio","g":"abemaciclib","c":"CDK4/6 Inhibitor","a":"FDA Approved 2017","m":"Eli Lilly","i":"HR+/HER2\u2212 Advanced or Metastatic Breast Cancer: In combination with an aromatase inhibitor as initial endocrine-based therapy in postmenopausal women and men. HR+/HER2\u2212 Advanced or Metastatic Breast Cancer: In combination with fulvestrant in patients with disease progression following endocrine therapy. HR+/HER2\u2212 Early Breast Cancer (adjuvant): In combination with endocrine therapy (tamoxifen or aromatase inhibitor) in adult patients with high risk of recurrence and Ki-67 score \u226520% (for node-po","d":"HR+/HER2\u2212 Advanced or Metastatic Breast Cancer: In combination with an aromatase inhibitor as initial endocrine-based therapy in postmenopausal women and men. HR+/HER2\u2212 Advanced or Metastatic Breast Cancer: In combination with fulvestrant in patients with disease progression following endocrine therapy. HR+/HER2\u2212 Early Breast Cancer (adjuvant): In combination with endocrine therapy (tamoxifen or a","ae":"","moa":"Abemaciclib is a selective inhibitor of CDK4 and CDK6 that are activated upon binding to D-cyclins. In ER+ breast cancer cell lines, abemaciclib (in combination with anti-estrogens) blocks Rb phosphorylation, preventing G1/S transition and inhibiting cell growth. Abemaciclib shows greater selectivity for CDK4/cyclin D1 over CDK6/cyclin D3 and is dosed continuously (unlike palbociclib/ribociclib) d","pk":"Tmax: 8 hours. Bioavailability: 45%. Vd: 690 L. Protein binding: 96%. Metabolized by CYP3A4 to active metabolites M2 (~25% parent exposure), M20 (~26%), M18 (~8%). Half-life: 18 hours. Steady state by Day 5. Elimination: feces 81%, urine 3%.","t":[]},{"s":"voranigo","b":"Voranigo","g":"vorasidenib","c":"Dual IDH1/IDH2 Inhibitor","a":"FDA Approved 2024","m":"Servier","i":"Grade 2 astrocytoma or oligodendroglioma with a susceptible isocitrate dehydrogenase-1 (IDH1) or IDH2 mutation, as detected by an FDA-approved test, in adults following a prior surgery that included biopsy, subtotal resection, or gross total resection.","d":"Grade 2 astrocytoma or oligodendroglioma with a susceptible isocitrate dehydrogenase-1 (IDH1) or IDH2 mutation, as detected by an FDA-approved test, in adults following a prior surgery that included biopsy, subtotal resection, or gross total resection.","ae":"Fatigue (27%), headache (23%), COVID-19 (23%), musculoskeletal pain (22%), diarrhea (18%), nausea (18%), seizure (15%), ALT increase (47%), AST increase (42%), GGT increase (36%), decreased appetite (10%)","moa":"Vorasidenib is a dual inhibitor of mutant IDH1 and mutant IDH2 enzymes, designed with brain penetrance. IDH1/2 mutations (R132H, R132C, R172K, etc.) are present in >80% of grade 2-3 gliomas and produce the oncometabolite D-2-hydroxyglutarate (2-HG), which drives epigenetic dysregulation and tumorigenesis. By inhibiting mutant IDH1 and IDH2, vorasidenib reduces intratumoral 2-HG levels, allowing re","pk":"Tmax: 2-4 hours. Half-life: approximately 80-100 hours (long). Protein binding: >99%. CNS penetrance: demonstrated brain/plasma ratio in preclinical studies. Metabolized by CYP3A4. Steady-state: ~3 weeks. Excreted in feces (>70%).","t":[{"name":"INDIGO","desc":"Vorasidenib vs. placebo in IDH-mutant grade 2 glioma after surgery. Phase III, n=331."}]},{"s":"votrient","b":"Votrient","g":"","c":"Multi-Kinase Inhibitor (VEGFR/PDGFR/KIT)","a":"FDA Approved 2009","m":"Novartis","i":"Advanced renal cell carcinoma (RCC); Advanced soft tissue sarcoma (STS) \u2014 previously treated with chemotherapy.","d":"Advanced renal cell carcinoma (RCC); Advanced soft tissue sarcoma (STS) \u2014 previously treated with chemotherapy.","ae":"","moa":"","pk":"","t":[{"name":"VEG105192","desc":"Pazopanib vs. placebo in advanced/metastatic RCC. Phase III, n=435."}]},{"s":"vyxeos","b":"Vyxeos","g":"daunorubicin and cytarabine liposome","c":"Liposomal Anthracycline + Antimetabolite","a":"FDA Approved 2017","m":"Jazz Pharmaceuticals","i":"Acute myeloid leukemia (AML) \u2014 newly diagnosed, therapy-related AML (t-AML) or AML with myelodysplasia-related changes (AML-MRC) in adults","d":"Acute myeloid leukemia (AML) \u2014 newly diagnosed, therapy-related AML (t-AML) or AML with myelodysplasia-related changes (AML-MRC) in adults","ae":"Hemorrhage (69%), febrile neutropenia (68%), rash (44%), edema (35%), nausea (33%), mucositis (32%), diarrhea (32%), constipation (28%), musculoskeletal pain (26%), fatigue (26%), abdominal pain (23%), dyspnea (23%), headache (21%), cough (19%), decreased appetite (21%), arrhythmia (18%), pneumonia (17%), bacteremia (17%)","moa":"Vyxeos is a liposomal formulation that encapsulates daunorubicin and cytarabine in a fixed 1:5 molar ratio within bilamellar liposomes. This ratio was selected to maximize synergistic anti-leukemic activity in vitro and in vivo. The liposomal formulation maintains this synergistic drug ratio in plasma and bone marrow for over 24 hours after administration, improving drug delivery to leukemia cells","pk":"Daunorubicin half-life: 31.5 hours; Cytarabine half-life: 40.4 hours. Liposomal encapsulation maintains 5:1 molar ratio (cytarabine:daunorubicin) in plasma and bone marrow. Vd: 4.8 L (daunorubicin), 6.6 L (cytarabine). Limited renal excretion.","t":[]},{"s":"welireg","b":"Welireg","g":"belzutifan","c":"HIF-2\u03b1 Inhibitor","a":"FDA Approved 2021","m":"Merck & Co.","i":"Von Hippel-Lindau (VHL) disease-associated renal cell carcinoma (RCC), central nervous system hemangioblastomas, or pancreatic neuroendocrine tumors (pNET) not requiring immediate surgery; Advanced renal cell carcinoma (with cabozantinib and nivolumab, after prior anti-PD-1/PD-L1 therapy)","d":"Von Hippel-Lindau (VHL) disease-associated renal cell carcinoma (RCC), central nervous system hemangioblastomas, or pancreatic neuroendocrine tumors (pNET) not requiring immediate surgery; Advanced renal cell carcinoma (with cabozantinib and nivolumab, after prior anti-PD-1/PD-L1 therapy)","ae":"Anemia (93%), fatigue (51%), musculoskeletal pain (30%), dizziness (20%), headache (17%), nausea (16%), decreased visual acuity (13%)","moa":"Belzutifan is an inhibitor of hypoxia-inducible factor 2 alpha (HIF-2\u03b1). In VHL disease, inactivation of the VHL tumor suppressor gene leads to accumulation of HIF-2\u03b1 and subsequent transcription of genes promoting tumor growth, angiogenesis, and erythropoiesis. Belzutifan blocks the interaction between HIF-2\u03b1 and HIF-1\u03b2 (ARNT), thereby reducing transcription of HIF-2\u03b1 target genes including VEGFA","pk":"Tmax: 1.5 hours. Half-life: approximately 14 hours. Protein binding: 97%. Metabolized by CYP2C19 and UGT2B17. Excreted in urine (47%) and feces (41%).","t":[]},{"s":"xalkori","b":"Xalkori","g":"","c":"ALK/ROS1/MET Inhibitor","a":"FDA Approved 2011","m":"Pfizer","i":"Metastatic non-small cell lung cancer (NSCLC) whose tumors are anaplastic lymphoma kinase (ALK)-positive as detected by an FDA-approved test; Metastatic NSCLC whose tumors are ROS1-positive; ALK-positive unresectable, recurrent, or refractory inflammatory myofibroblastic tumors (IMT) in adults and pediatric patients 1 year and older; Relapsed or refractory ALK-positive anaplastic large cell lymphoma (ALCL) in pediatric patients 1 year and older.","d":"Metastatic non-small cell lung cancer (NSCLC) whose tumors are anaplastic lymphoma kinase (ALK)-positive as detected by an FDA-approved test; Metastatic NSCLC whose tumors are ROS1-positive; ALK-positive unresectable, recurrent, or refractory inflammatory myofibroblastic tumors (IMT) in adults and pediatric patients 1 year and older; Relapsed or refractory ALK-positive anaplastic large cell lympho","ae":"","moa":"","pk":"","t":[]},{"s":"xermelo","b":"Xermelo","g":"","c":"Tryptophan Hydroxylase Inhibitor","a":"FDA Approved 2017","m":"TerSera Therapeutics","i":"Carcinoid syndrome diarrhea in combination with somatostatin analog (SSA) therapy in adults inadequately controlled by SSA therapy alone.","d":"Carcinoid syndrome diarrhea in combination with somatostatin analog (SSA) therapy in adults inadequately controlled by SSA therapy alone.","ae":"","moa":"","pk":"","t":[{"name":"TELESTAR","desc":"Telotristat ethyl vs. placebo for carcinoid syndrome diarrhea. Phase III, n=135."}]},{"s":"xofigo","b":"Xofigo","g":"","c":"Alpha-Emitting Radiopharmaceutical","a":"FDA Approved 2013","m":"Bayer","i":"Castration-resistant prostate cancer (CRPC) with symptomatic bone metastases and no known visceral metastatic disease.","d":"Castration-resistant prostate cancer (CRPC) with symptomatic bone metastases and no known visceral metastatic disease.","ae":"","moa":"","pk":"","t":[{"name":"ALSYMPCA","desc":"Radium-223 vs. placebo in mCRPC with bone metastases. Phase III, n=921."}]},{"s":"xospata","b":"Xospata","g":"gilteritinib","c":"FLT3 Inhibitor","a":"FDA Approved 2018","m":"Astellas","i":"Acute myeloid leukemia (AML) \u2014 relapsed or refractory, with a FLT3 mutation as detected by an FDA-approved test","d":"Acute myeloid leukemia (AML) \u2014 relapsed or refractory, with a FLT3 mutation as detected by an FDA-approved test","ae":"Myalgia/arthralgia (46%), transaminase increased (41%), fatigue/malaise (36%), fever (35%), noninfectious diarrhea (35%), dyspnea (35%), edema (34%), rash (30%), pneumonia (30%), nausea (27%), stomatitis (26%), cough (24%), headache (21%), hypotension (21%)","moa":"Gilteritinib is an inhibitor of multiple receptor tyrosine kinases including FMS-like tyrosine kinase 3 (FLT3). It inhibits FLT3 receptor signaling and proliferation in cells expressing FLT3 internal tandem duplication (ITD) and tyrosine kinase domain (TKD) mutations (D835Y and D835H). It also inhibits AXL kinase.","pk":"Tmax: 4-6 hours. Half-life: approximately 113 hours. Protein binding: 90.7%. Primarily metabolized by CYP3A4. Fecal excretion (64%), urinary excretion (16%).","t":[{"name":"ADMIRAL","desc":"Gilteritinib vs. salvage chemotherapy in FLT3-mutated relapsed/refractory AML. Phase III, n=371."}]},{"s":"xpovio","b":"Xpovio","g":"selinexor","c":"Nuclear Export Inhibitor (XPO1/CRM1)","a":"FDA Approved 2019","m":"Karyopharm Therapeutics","i":"Multiple myeloma \u2014 in combination with bortezomib and dexamethasone for adult patients who have received at least one prior therapy; in combination with dexamethasone for adults with relapsed/refractory disease after at least four prior therapies; Diffuse large B-cell lymphoma (DLBCL) \u2014 relapsed or refractory after at least two lines of systemic therapy","d":"Multiple myeloma \u2014 in combination with bortezomib and dexamethasone for adult patients who have received at least one prior therapy; in combination with dexamethasone for adults with relapsed/refractory disease after at least four prior therapies; Diffuse large B-cell lymphoma (DLBCL) \u2014 relapsed or refractory after at least two lines of systemic therapy","ae":"Thrombocytopenia (74%), fatigue (63%), nausea (72%), anorexia/weight loss (53%), anemia (59%), diarrhea (44%), vomiting (41%), hyponatremia (39%), neutropenia (34%), leukopenia (29%), constipation (17%)","moa":"Selinexor is a first-in-class selective inhibitor of nuclear export (SINE) compound that blocks Exportin 1 (XPO1, also known as CRM1). XPO1 mediates the nuclear export of over 200 cargo proteins, including tumor suppressor proteins (p53, Rb, p21, p27, FOXO, I\u03baB) and oncoproteins (c-Myc, Cyclin D1). By inhibiting XPO1, selinexor causes nuclear accumulation and functional restoration of tumor suppre","pk":"Tmax: approximately 4 hours. Half-life: 6-8 hours. Protein binding: 95%. Metabolized by CYP3A4 and multiple other CYP enzymes and glucuronidation. Excreted in feces and urine.","t":[{"name":"STORM","desc":"Selinexor + dexamethasone in penta-refractory MM. Phase IIb, n=123."}]},{"s":"xtandi","b":"Xtandi","g":"","c":"Androgen Receptor Inhibitor","a":"FDA Approved 2012","m":"Pfizer/Astellas","i":"Castration-resistant prostate cancer (CRPC) \u2014 metastatic CRPC (both pre- and post-chemotherapy); Non-metastatic CRPC (nmCRPC) with rapidly rising PSA; Metastatic castration-sensitive prostate cancer (mCSPC).","d":"Castration-resistant prostate cancer (CRPC) \u2014 metastatic CRPC (both pre- and post-chemotherapy); Non-metastatic CRPC (nmCRPC) with rapidly rising PSA; Metastatic castration-sensitive prostate cancer (mCSPC).","ae":"","moa":"","pk":"","t":[{"name":"AFFIRM","desc":"Enzalutamide vs. placebo in post-chemotherapy mCRPC. Phase III, n=1199."},{"name":"PREVAIL","desc":"Enzalutamide vs. placebo in chemotherapy-na\u00efve mCRPC. Phase III, n=1717."}]},{"s":"yervoy","b":"Yervoy","g":"","c":"CTLA-4 Inhibitor","a":"FDA Approved 2011","m":"BMS","i":"Unresectable or metastatic melanoma (monotherapy or with nivolumab); Adjuvant treatment of cutaneous melanoma with pathologic involvement of regional lymph nodes >1 mm who have undergone complete resection; Advanced renal cell carcinoma (with nivolumab, first-line intermediate/poor risk); Microsatellite instability-high (MSI-H) or mismatch repair deficient (dMMR) metastatic colorectal cancer (with nivolumab, after prior fluoropyrimidine/oxaliplatin/irinotecan); Hepatocellular carcinoma (with niv","d":"Unresectable or metastatic melanoma (monotherapy or with nivolumab); Adjuvant treatment of cutaneous melanoma with pathologic involvement of regional lymph nodes >1 mm who have undergone complete resection; Advanced renal cell carcinoma (with nivolumab, first-line intermediate/poor risk); Microsatellite instability-high (MSI-H) or mismatch repair deficient (dMMR) metastatic colorectal cancer (with","ae":"","moa":"","pk":"","t":[{"name":"MDX010-20","desc":"Ipilimumab \u00b1 gp100 vaccine vs. gp100 alone in previously treated metastatic melanoma. Phase III, n=676."}]},{"s":"yescarta","b":"Yescarta","g":"axicabtagene ciloleucel","c":"CAR T-Cell Therapy (CD19-targeted)","a":"FDA Approved 2017","m":"Kite/Gilead Sciences","i":"Large B-cell lymphoma \u2014 relapsed or refractory after two or more lines of systemic therapy (DLBCL NOS, primary mediastinal large B-cell lymphoma, high-grade B-cell lymphoma, DLBCL arising from follicular lymphoma); Large B-cell lymphoma \u2014 relapsed or refractory within 12 months of first-line chemoimmunotherapy or refractory to first-line chemoimmunotherapy; Follicular lymphoma (FL) \u2014 relapsed or refractory after two or more lines of systemic therapy","d":"Large B-cell lymphoma \u2014 relapsed or refractory after two or more lines of systemic therapy (DLBCL NOS, primary mediastinal large B-cell lymphoma, high-grade B-cell lymphoma, DLBCL arising from follicular lymphoma); Large B-cell lymphoma \u2014 relapsed or refractory within 12 months of first-line chemoimmunotherapy or refractory to first-line chemoimmunotherapy; Follicular lymphoma (FL) \u2014 relapsed or r","ae":"CRS (93%), fever (85%), fatigue (46%), hypotension (43%), encephalopathy (34%), tachycardia (33%), nausea (30%), headache (29%), chills (28%), diarrhea (23%), febrile neutropenia (22%), infections (22%)","moa":"Axicabtagene ciloleucel is a CD19-directed genetically modified autologous T-cell immunotherapy. Patient T cells are collected via leukapheresis and genetically modified ex vivo using a retroviral vector to express a chimeric antigen receptor (CAR) comprising an anti-CD19 single-chain variable fragment (scFv) linked to CD28 costimulatory and CD3-zeta signaling domains. Upon infusion and engagement","pk":"Peak CAR T-cell expansion: median 8-15 days post-infusion. CAR T cells detectable in blood for 6+ months (though declining). CD28 costimulatory domain drives rapid initial expansion. Higher Cmax correlated with Grade 3+ CRS and response.","t":[{"name":"ZUMA-1","desc":"Axicabtagene ciloleucel in relapsed/refractory large B-cell lymphoma. Phase I/II, n=101."},{"name":"ZUMA-7","desc":"Axicabtagene ciloleucel vs. standard of care in 2L relapsed/refractory LBCL. Phase III, n=359."}]},{"s":"zynlonta","b":"Zynlonta","g":"loncastuximab tesirine-lpyl","c":"Antibody-Drug Conjugate (CD19-targeted)","a":"FDA Approved 2021","m":"ADC Therapeutics","i":"Large B-cell lymphoma \u2014 relapsed or refractory, after two or more lines of systemic therapy, including DLBCL NOS, DLBCL arising from low-grade lymphoma, and high-grade B-cell lymphoma","d":"Large B-cell lymphoma \u2014 relapsed or refractory, after two or more lines of systemic therapy, including DLBCL NOS, DLBCL arising from low-grade lymphoma, and high-grade B-cell lymphoma","ae":"Thrombocytopenia (32%), neutropenia (26%), increased GGT (22%), fatigue (27%), rash (30%), edema (37%), nausea (23%), musculoskeletal pain (23%), infection (28%), diarrhea (12%), dyspnea (13%)","moa":"Loncastuximab tesirine is an antibody-drug conjugate consisting of a humanized anti-CD19 IgG1 monoclonal antibody conjugated to a pyrrolobenzodiazepine (PBD) dimer cytotoxin (SG3199) via a cathepsin-cleavable valine-alanine linker. Upon binding CD19 on B cells and internalization, the PBD dimer is released and crosslinks DNA via the minor groove, blocking DNA replication and inducing cell death. P","pk":"ADC half-life: approximately 12 days. Payload (SG3199/PBD dimer) half-life: 6-10 days. Steady-state by Cycle 3. Clearance: 0.29 L/day. Vd: 7.5 L. PBD dimer binds in DNA minor groove forming interstrand crosslinks.","t":[{"name":"LOTIS-2","desc":"Loncastuximab tesirine in relapsed/refractory DLBCL after \u22652 prior lines. Phase II, n=145."}]},{"s":"zytiga","b":"Zytiga","g":"","c":"CYP17 Inhibitor","a":"FDA Approved 2011","m":"Janssen","i":"Metastatic castration-resistant prostate cancer (mCRPC); Metastatic high-risk castration-sensitive prostate cancer (mCSPC) \u2014 in combination with prednisone.","d":"Metastatic castration-resistant prostate cancer (mCRPC); Metastatic high-risk castration-sensitive prostate cancer (mCSPC) \u2014 in combination with prednisone.","ae":"","moa":"","pk":"","t":[]}];